-- ============================================================================
-- Quiz Seed: 2 Chronicles — Part 3 (Chapters 25–36)
-- 3 kids + 5 teens + 8 adults = 16 questions × 12 chapters = 192 total questions
-- ============================================================================

-- ═══ 2 Chronicles Chapter 25 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 25, 'kids', 1, 'Who was the king of Judah in this chapter?', 'Amaziah', 'Uzziah', 'Hezekiah', 'Josiah', 'a', '2 Chronicles 25:1 — "Amaziah was twenty and five years old when he began to reign, and he reigned twenty and nine years in Jerusalem."'),
('2 Chronicles', 25, 'kids', 2, 'What people did Amaziah defeat in battle?', 'The Edomites', 'The Philistines', 'The Assyrians', 'The Egyptians', 'a', '2 Chronicles 25:11 — "And Amaziah strengthened himself, and led forth his people, and went to the valley of salt, and smote of the children of Seir ten thousand."'),
('2 Chronicles', 25, 'kids', 3, 'After defeating Edom, what did Amaziah foolishly bring back and worship?', 'The gods of the children of Seir', 'Gold idols from Egypt', 'Silver statues from Babylon', 'Bronze calves from Israel', 'a', '2 Chronicles 25:14 — "Now it came to pass, after that Amaziah was come from the slaughter of the Edomites, that he brought the gods of the children of Seir, and set them up to be his gods, and bowed down himself before them."'),
-- Teens
('2 Chronicles', 25, 'teens', 1, 'What did the man of God tell Amaziah about the hundred talents of silver he had paid to hire soldiers from Israel?', 'That God was not with Israel and Amaziah should send them home, for God was able to give him much more than that', 'That he should use the soldiers since he had already paid for them', 'That he should keep them as a reserve force', 'That the silver would be repaid out of the spoil of Edom', 'a', '2 Chronicles 25:9 — "And Amaziah said to the man of God, But what shall we do for the hundred talents which I have given to the army of Israel? And the man of God answered, The LORD is able to give thee much more than this."'),
('2 Chronicles', 25, 'teens', 2, 'What did the dismissed Israelite soldiers do as they returned home angry?', 'They fell upon the cities of Judah and smote three thousand and took much spoil', 'They ambushed the Edomite army', 'They attacked the caravan roads', 'They complained to the king of Israel', 'a', '2 Chronicles 25:13 — "But the soldiers of the army which Amaziah sent back...fell upon the cities of Judah...and smote three thousand of them, and took much spoil."'),
('2 Chronicles', 25, 'teens', 3, 'How did Amaziah challenge Joash king of Israel, and what was Joash''s response using a parable?', 'Amaziah challenged him to battle; Joash replied with a parable of a thistle asking a cedar to give his daughter in marriage, warning Amaziah not to stir up trouble', 'Amaziah demanded tribute; Joash laughed and sent it', 'Amaziah asked for an alliance; Joash agreed and they met at Samaria', 'Amaziah invaded first; Joash counter-attacked without warning', 'a', '2 Chronicles 25:18 — "And Joash king of Israel sent to Amaziah king of Judah, saying, The thistle that was in Lebanon sent to the cedar that was in Lebanon, saying, Give thy daughter to my son to wife."'),
('2 Chronicles', 25, 'teens', 4, 'What happened when Amaziah would not listen to Joash''s warning and the battle was fought at Beth-shemesh?', 'Judah was put to the worse before Israel, and Amaziah king of Judah was taken prisoner', 'Judah defeated Israel and Joash fled', 'Both armies retreated without a decisive result', 'Amaziah escaped but his army was captured', 'a', '2 Chronicles 25:22 — "And Judah was put to the worse before Israel, and they fled every man to his tent."'),
('2 Chronicles', 25, 'teens', 5, 'How did Amaziah''s reign end?', 'He was killed at Lachish after fleeing there from a conspiracy in Jerusalem', 'He died peacefully in Jerusalem after a long reign', 'He was taken captive to Babylon', 'He was struck with leprosy like Uzziah', 'a', '2 Chronicles 25:27-28 — "They sent to Lachish after him, and slew him there...and they buried him with his fathers in the city of Judah."'),
-- Adults
('2 Chronicles', 25, 'adults', 1, 'What qualification does the Chronicler give for Amaziah''s character at the outset, and what does this phrase suggest about the limits of his devotion?', 'He did that which was right in the sight of the LORD, but not with a perfect heart', 'He was wholly faithful but lacked military skill', 'He kept the law perfectly but was proud', 'He was righteous in his youth but fell away in old age', 'a', '2 Chronicles 25:2 — "And he did that which was right in the sight of the LORD, but not with a perfect heart."'),
('2 Chronicles', 25, 'adults', 2, 'How did Amaziah handle the men who had murdered his father, and what law did he cite in doing so?', 'He killed only the murderers but not their children, as written in the law of Moses that fathers shall not die for their children', 'He executed the entire families of the conspirators', 'He exiled the murderers to the wilderness', 'He forgave them according to his priestly advisors'' counsel', 'a', '2 Chronicles 25:4 — "But he slew not their children, but did as it is written in the law in the book of Moses, where the LORD commanded, saying, The fathers shall not die for the children."'),
('2 Chronicles', 25, 'adults', 3, 'How many Edomites were killed in the valley of salt and at the cliff, and what was done at the cliff?', 'Ten thousand were slain in the valley of salt, and ten thousand were cast down from the cliff so that they all were broken in pieces', 'Twenty thousand slain in battle and five thousand taken captive', 'Thirty thousand slain with the sword alone', 'Fifteen thousand slain and the rest enslaved', 'a', '2 Chronicles 25:11-12 — "And Amaziah...smote of the children of Seir ten thousand. And other ten thousand left alive did the children of Judah carry away captive, and brought them unto the top of the rock, and cast them down from the top of the rock, that they all were broken in pieces."'),
('2 Chronicles', 25, 'adults', 4, 'When the prophet warned Amaziah about worshipping Edomite gods, what was Amaziah''s arrogant reply, and what did the prophet say in return?', 'Amaziah asked who made the prophet a counsellor to the king; the prophet said he knew God had determined to destroy Amaziah because he had done this', 'Amaziah imprisoned the prophet immediately', 'Amaziah repented and destroyed the idols', 'Amaziah ignored the prophet without speaking', 'a', '2 Chronicles 25:16 — "Then the prophet forbare, and said, I know that God hath determined to destroy thee, because thou hast done this, and hast not hearkened unto my counsel."'),
('2 Chronicles', 25, 'adults', 5, 'What specific damage did Joash do to Jerusalem after defeating Amaziah?', 'He broke down four hundred cubits of the wall of Jerusalem from the gate of Ephraim to the corner gate, took all the gold, silver, and vessels in the house of God, and took hostages', 'He burned the temple and carried off only the priests', 'He took only the king''s treasury and left the city intact', 'He demolished the palace but spared the temple', 'a', '2 Chronicles 25:23-24 — "And Joash...broke down the wall of Jerusalem from the gate of Ephraim to the corner gate, four hundred cubits. And he took all the gold and the silver, and all the vessels...and returned to Samaria."'),
('2 Chronicles', 25, 'adults', 6, 'What theological explanation does the Chronicler give for Amaziah''s refusal to heed Joash''s parable warning?', 'It came of God, that he might deliver them into the hand of their enemies, because they sought after the gods of Edom', 'Amaziah was proud from his victory over Edom', 'His advisors had convinced him Israel was weak', 'He misread the political situation and thought Joash was bluffing', 'a', '2 Chronicles 25:20 — "But Amaziah would not hear; for it came of God, that he might deliver them into the hand of their enemies, because they sought after the gods of Edom."'),
('2 Chronicles', 25, 'adults', 7, 'How many men of valour did Amaziah muster from Judah and Benjamin for his Edomite campaign?', 'Three hundred thousand choice men, able to go forth to war, that could handle spear and shield', 'One hundred thousand from Judah alone', 'Five hundred thousand from all twelve tribes', 'Two hundred thousand with one hundred thousand hired from Israel', 'a', '2 Chronicles 25:5 — "He gathered Judah together, and made them captains over thousands, and captains over hundreds...and found them three hundred thousand choice men, able to go forth to war."'),
('2 Chronicles', 25, 'adults', 8, 'What was the sum Amaziah paid to hire men of valour from Israel, and why was this a spiritually costly decision?', 'A hundred talents of silver; it was costly because God was not with Israel and it showed Amaziah''s lack of faith in God''s sufficiency alone', 'A thousand talents of gold; it depleted Judah''s treasury fatally', 'Ten talents of silver; a small sum showing contempt for Israel', 'Fifty talents of silver; acceptable because it was a defensive alliance', 'a', '2 Chronicles 25:6 — "He hired also an hundred thousand mighty men of valour out of Israel for an hundred talents of silver."');

-- ═══ 2 Chronicles Chapter 26 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 26, 'kids', 1, 'Who was the king of Judah who became a leper?', 'Uzziah', 'Hezekiah', 'Josiah', 'Amaziah', 'a', '2 Chronicles 26:19 — "Then Uzziah was wroth, and had a censer in his hand to burn incense: and while he was wroth with the priests, the leprosy even rose up in his forehead before the priests in the house of the LORD."'),
('2 Chronicles', 26, 'kids', 2, 'Why was Uzziah struck with leprosy?', 'He went into the temple to burn incense, which only priests were allowed to do', 'He broke God''s Sabbath laws', 'He married a foreign wife', 'He worshipped idols in the high places', 'a', '2 Chronicles 26:16 — "But when he was strong, his heart was lifted up to his destruction: for he transgressed against the LORD his God, and went into the temple of the LORD to burn incense upon the altar of incense."'),
('2 Chronicles', 26, 'kids', 3, 'As long as Uzziah sought the LORD, who helped him to prosper?', 'God made him to prosper', 'The prophet Isaiah guided him', 'The priests prayed for him daily', 'His father Amaziah taught him wisdom', 'a', '2 Chronicles 26:5 — "And he sought God in the days of Zechariah, who had understanding in the visions of God: and as long as he sought the LORD, God made him to prosper."'),
-- Teens
('2 Chronicles', 26, 'teens', 1, 'What prophet instructed Uzziah and helped him seek God in his early years?', 'Zechariah, who had understanding in the visions of God', 'Isaiah the son of Amoz', 'Amos the herdsman from Tekoa', 'Micah of Moresheth', 'a', '2 Chronicles 26:5 — "And he sought God in the days of Zechariah, who had understanding in the visions of God."'),
('2 Chronicles', 26, 'teens', 2, 'What were three areas in which Uzziah''s military power was strengthened?', 'He had an army of 307,500 soldiers, built towers in Jerusalem and the wilderness, and invented engines of war for the towers', 'He conquered Egypt, Philistia, and Edom', 'He built a navy, fortified Judah''s borders, and trained cavalry', 'He hired foreign mercenaries, built siege weapons, and dug water channels', 'a', '2 Chronicles 26:12-15 — "The whole number of the chief of the fathers of the mighty men of valour were two thousand and six hundred...And the number of all their host was three hundred thousand and seven thousand and five hundred...And he made in Jerusalem engines, invented by cunning men, to be on the towers."'),
('2 Chronicles', 26, 'teens', 3, 'What three groups did Uzziah defeat or subdue during his reign?', 'The Philistines, the Arabians at Gur-baal, and the Mehunim', 'The Egyptians, the Moabites, and the Edomites', 'The Assyrians, the Syrians, and the Ammonites', 'The Amalekites, the Hivites, and the Perizzites', 'a', '2 Chronicles 26:7 — "And God helped him against the Philistines, and against the Arabians that dwelt in Gur-baal, and the Mehunim."'),
('2 Chronicles', 26, 'teens', 4, 'What happened when Uzziah entered the temple to burn incense and the priests confronted him?', 'Uzziah was wroth with the priests, and leprosy rose in his forehead before them in the house of the LORD', 'He repented and left immediately without consequence', 'The priests allowed him to continue since he was king', 'Fire fell from heaven and consumed the altar', 'a', '2 Chronicles 26:19 — "Then Uzziah was wroth, and had a censer in his hand to burn incense: and while he was wroth with the priests, the leprosy even rose up in his forehead before the priests."'),
('2 Chronicles', 26, 'teens', 5, 'Where did Uzziah live after he was struck with leprosy, and who governed in his place?', 'He dwelt in a several house, being a leper, and Jotham his son was over the king''s house, judging the people', 'He was sent to a leper colony outside Judah', 'He went to Egypt for healing', 'He remained in the palace but was hidden from public view', 'a', '2 Chronicles 26:21 — "And Uzziah the king was a leper unto the day of his death, and dwelt in a several house, being a leper; for he was cut off from the house of the LORD: and Jotham his son was over the king''s house, judging the people of the land."'),
-- Adults
('2 Chronicles', 26, 'adults', 1, 'What does the phrase "his heart was lifted up to his destruction" tell us theologically about the relationship between prosperity and pride in the Chronicler''s view?', 'That God-given success became the very occasion of Uzziah''s fall, teaching that strength and pride lead to transgression without continual dependence on God', 'That Uzziah was inherently wicked from the beginning', 'That material success is itself a spiritual danger to be avoided', 'That God withdrew his blessing once the temple was built', 'a', '2 Chronicles 26:16 — "But when he was strong, his heart was lifted up to his destruction: for he transgressed against the LORD his God."'),
('2 Chronicles', 26, 'adults', 2, 'How many priests withstood Uzziah when he entered the temple, and what did they declare to him?', 'Fourscore priests of valour, who said it appertaineth not unto thee, Uzziah, to burn incense unto the LORD, but to the priests the sons of Aaron that are consecrated to burn incense', 'Twelve chief priests representing the twelve tribes', 'Only the high priest Azariah alone confronted him', 'Seven priests as required by the law of Moses', 'a', '2 Chronicles 26:17-18 — "And Azariah the priest went in after him, and with him fourscore priests of the LORD, that were valiant men: And they withstood Uzziah the king, and said unto him...It appertaineth not unto thee, Uzziah, to burn incense."'),
('2 Chronicles', 26, 'adults', 3, 'What territories did Uzziah build cities in after breaking down Philistine walls, and what tribute did the Ammonites pay?', 'He built cities about Ashdod and in Philistia, and the Ammonites gave gifts, his name spreading to Egypt', 'He rebuilt only Jerusalem''s walls', 'He conquered only the coastal plain and demanded no tribute', 'He built only military outposts in the Negev', 'a', '2 Chronicles 26:6-8 — "And he went forth and warred against the Philistines, and brake down the wall of Gath, and the wall of Jabneh, and the wall of Ashdod, and built cities about Ashdod...And the Ammonites gave gifts to Uzziah: and his name spread abroad even to the entering in of Egypt."'),
('2 Chronicles', 26, 'adults', 4, 'What agricultural and pastoral activities does the Chronicler mention to show Uzziah''s love of the land?', 'He had husbandmen and vinedressers in the mountains and in Carmel, for he loved husbandry, and also much cattle in the lowlands', 'He built irrigation canals throughout Judah', 'He imported grain from Egypt to fill storehouses', 'He planted forests and orchards around Jerusalem', 'a', '2 Chronicles 26:10 — "Also he built towers in the desert, and digged many wells: for he had much cattle, both in the low country, and in the plains: husbandmen also, and vine dressers in the mountains, and in Carmel: for he loved husbandry."'),
('2 Chronicles', 26, 'adults', 5, 'What specific equipment are the "engines invented by cunning men" described as being used for, and where were they placed?', 'They were placed on towers and on bulwarks to shoot arrows and great stones, and Uzziah''s name spread abroad because of his great strength', 'They were siege machines used to attack enemy cities', 'They were agricultural devices to assist in harvest', 'They were water-lifting machines for the desert wells', 'a', '2 Chronicles 26:15 — "And he made in Jerusalem engines, invented by cunning men, to be on the towers and upon the bulwarks, to shoot arrows and great stones withal: and his name spread far abroad."'),
('2 Chronicles', 26, 'adults', 6, 'What was Uzziah''s age at accession, the length of his reign, and the name of the historian who recorded his acts?', 'He was sixteen when he began to reign, reigned fifty-two years, and his acts were written by Isaiah the prophet the son of Amoz', 'He was twenty-five, reigned forty years, written by Jeremiah', 'He was eighteen, reigned forty-five years, written by Ezra', 'He was twenty, reigned thirty years, written by Nathan', 'a', '2 Chronicles 26:1,3,22 — "Uzziah, who was sixteen years old...reigned fifty and two years in Jerusalem...Now the rest of the acts of Uzziah, first and last, did Isaiah the prophet, the son of Amoz, write."'),
('2 Chronicles', 26, 'adults', 7, 'What happened to Uzziah when he died as a leper, and how was his burial affected by his condition?', 'He was buried in the field of the burial which belonged to the kings, for they said he is a leper, not in the royal sepulchres', 'He was buried with full honours in the royal tombs', 'He was buried outside the city in an unmarked grave', 'He was buried at Gibeon by the priests', 'a', '2 Chronicles 26:23 — "So Uzziah slept with his fathers, and they buried him with his fathers in the field of the burial which belonged to the kings; for they said, He is a leper."'),
('2 Chronicles', 26, 'adults', 8, 'What does the Chronicler''s pairing of "God made him to prosper" (v.5) and "his heart was lifted up to his destruction" (v.16) reveal about the spiritual structure of his reign?', 'It reveals a pattern the Chronicler uses repeatedly: faithfulness brings blessing, but success without continued humility leads to pride and judgment — a central theme of Chronicles', 'It reveals that God''s blessings are always temporary and must be earned daily', 'It reveals Uzziah was weak-willed and easily corrupted', 'It reveals the priests had too much power over the king', 'a', '2 Chronicles 26:5,16 — The Chronicler deliberately frames Uzziah''s reign around these two verses to teach that seeking God is the only safeguard against the corruption of success.');

-- ═══ 2 Chronicles Chapter 27 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 27, 'kids', 1, 'Who was king of Judah in this chapter?', 'Jotham', 'Ahaz', 'Manasseh', 'Uzziah', 'a', '2 Chronicles 27:1 — "Jotham was twenty and five years old when he began to reign, and he reigned sixteen years in Jerusalem."'),
('2 Chronicles', 27, 'kids', 2, 'What gate did Jotham build on the temple mount?', 'The upper gate of the house of the LORD', 'The water gate of the city', 'The sheep gate by the brook', 'The dung gate of Jerusalem', 'a', '2 Chronicles 27:3 — "He built the high gate of the house of the LORD, and on the wall of Ophel he built much."'),
('2 Chronicles', 27, 'kids', 3, 'Jotham became mighty because he did what?', 'Prepared his ways before the LORD his God', 'Built the largest army in Judah''s history', 'Made an alliance with the king of Egypt', 'Destroyed all the high places in the land', 'a', '2 Chronicles 27:6 — "So Jotham became mighty, because he prepared his ways before the LORD his God."'),
-- Teens
('2 Chronicles', 27, 'teens', 1, 'What mistake that his father Uzziah made did Jotham carefully avoid?', 'He entered not into the temple of the LORD, unlike his father who intruded on the priests'' duties', 'He never made war against neighbouring nations', 'He never levied taxes on the people', 'He never hired foreign craftsmen', 'a', '2 Chronicles 27:2 — "And he did that which was right in the sight of the LORD, according to all that his father Uzziah did: howbeit he entered not into the temple of the LORD."'),
('2 Chronicles', 27, 'teens', 2, 'What nations did Jotham defeat or subdue during his reign?', 'The Ammonites, from whom he received tribute for three years', 'The Philistines and the Arabians', 'The Edomites and the Syrians', 'The Moabites and the Midianites', 'a', '2 Chronicles 27:5 — "He fought also with the king of the Ammonites, and prevailed against them. And the children of Ammon gave him the same year an hundred talents of silver."'),
('2 Chronicles', 27, 'teens', 3, 'What was the annual tribute Jotham received from the Ammonites for three years?', 'A hundred talents of silver, ten thousand measures of wheat, and ten thousand of barley', 'Two hundred talents of gold each year', 'Fifty talents of silver and twenty thousand sheep', 'A thousand talents of silver the first year only', 'a', '2 Chronicles 27:5 — "And the children of Ammon gave him the same year an hundred talents of silver, and ten thousand measures of wheat, and ten thousand of barley. So much did the children of Ammon pay him, both the second year, and the third."'),
('2 Chronicles', 27, 'teens', 4, 'What building projects did Jotham undertake besides the upper gate?', 'He built much on the wall of Ophel, built cities in the mountains of Judah, and built castles and towers in the forests', 'He rebuilt the entire Jerusalem wall that Joash had broken down', 'He constructed a new palace and royal treasury', 'He built a new altar for the temple court', 'a', '2 Chronicles 27:3-4 — "He built the high gate of the house of the LORD, and on the wall of Ophel he built much. Moreover he built cities in the mountains of Judah, and in the forests he built castles and towers."'),
('2 Chronicles', 27, 'teens', 5, 'What was the moral condition of the people of Judah during Jotham''s reign despite his own righteousness?', 'The people did yet corruptly', 'The people were faithful and worshipped only the LORD', 'The people followed Jotham''s example completely', 'The people were divided between two opinions', 'a', '2 Chronicles 27:2 — "And the people did yet corruptly."'),
-- Adults
('2 Chronicles', 27, 'adults', 1, 'What does the brief but positive account of Jotham suggest about the Chronicler''s evaluative criteria for kings?', 'That consistent faithfulness and preparation of one''s ways before God — even without dramatic reform — constitutes a good reign worthy of divine blessing', 'That military success is the primary measure of a godly king', 'That building projects demonstrate God''s favour upon a reign', 'That tribute from foreign nations signals divine approval', 'a', '2 Chronicles 27:6 — "So Jotham became mighty, because he prepared his ways before the LORD his God," showing internal faithfulness as the foundation of external blessing.'),
('2 Chronicles', 27, 'adults', 2, 'How does the Chronicler''s note that "the people did yet corruptly" function within his theological framework?', 'It shows that a king''s personal righteousness does not automatically transform the people, and that national corruption persists independently of royal piety', 'It suggests Jotham was secretly wicked', 'It explains why God eventually punished Jotham', 'It shows the Levites were failing in their teaching duties', 'a', '2 Chronicles 27:2 — "And the people did yet corruptly," — a rare instance where the Chronicler separates kingly virtue from national spiritual condition.'),
('2 Chronicles', 27, 'adults', 3, 'What was Jotham''s age at accession and the total length of his reign?', 'He was twenty-five years old when he began to reign and reigned sixteen years in Jerusalem', 'He was twenty years old and reigned twenty years', 'He was eighteen and reigned twelve years', 'He was thirty and reigned twenty-five years', 'a', '2 Chronicles 27:1 — "Jotham was twenty and five years old when he began to reign, and he reigned sixteen years in Jerusalem."'),
('2 Chronicles', 27, 'adults', 4, 'What was his mother''s name and her father''s identity?', 'His mother''s name was Jerushah the daughter of Zadok', 'His mother''s name was Athaliah the daughter of Ahab', 'His mother''s name was Abijah the daughter of Zechariah', 'His mother''s name was Meshullemeth the daughter of Haruz', 'a', '2 Chronicles 27:1 — "His mother''s name also was Jerushah, the daughter of Zadok."'),
('2 Chronicles', 27, 'adults', 5, 'Where does the Chronicler direct readers who want to learn more about Jotham''s acts and wars?', 'To the book of the kings of Israel and Judah', 'To the writings of the prophet Isaiah', 'To the records of the priests at Jerusalem', 'To the chronicles of the kings of Judah', 'a', '2 Chronicles 27:7 — "Now the rest of the acts of Jotham, and all his wars, and his ways, lo, they are written in the book of the kings of Israel and Judah."'),
('2 Chronicles', 27, 'adults', 6, 'What theological significance does the Chronicler attach to Jotham''s building of the upper gate of the temple?', 'It reflects his respect for the sanctity of the temple and his desire to honour God''s house without presuming priestly privileges as his father had done', 'It was a purely defensive military measure', 'It demonstrated his wealth and power to surrounding nations', 'It fulfilled a prophecy made in the days of Solomon', 'a', '2 Chronicles 27:3 — "He built the high gate of the house of the LORD," which the Chronicler contrasts implicitly with Uzziah''s unlawful entry into the same temple.'),
('2 Chronicles', 27, 'adults', 7, 'How does the shortness of Jotham''s chapter compared to those of Hezekiah and Josiah reflect the Chronicler''s literary strategy?', 'The Chronicler gives proportionate space to reigns proportionate to their significance as reform movements — Jotham was faithful but not a major reformer', 'The Chronicler had fewer sources for Jotham', 'Jotham''s reign was deliberately minimized to contrast with evil Ahaz', 'Jotham''s records were lost in the Babylonian exile', 'a', '2 Chronicles 27:9 — "So Jotham slept with his fathers, and they buried him in the city of David," a quiet, dignified conclusion matching his quiet, faithful reign.'),
('2 Chronicles', 27, 'adults', 8, 'How does Jotham''s succession pattern compare with the pattern of other kings in Chronicles, and what does it reveal about dynastic stability during periods of faithfulness?', 'His son Ahaz reigned in his stead, showing that faithfulness in one generation does not guarantee it in the next — a recurring Chronicler warning', 'Jotham''s son continued his reforms and exceeded them', 'The succession was disputed and nearly broke the Davidic line', 'Jotham reigned jointly with Ahaz for ten years', 'a', '2 Chronicles 27:9 — "And Ahaz his son reigned in his stead," — Ahaz immediately reversed all his father''s godly ways, a sobering sequel to Jotham''s faithful reign.');

-- ═══ 2 Chronicles Chapter 28 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 28, 'kids', 1, 'King Ahaz of Judah did evil things. What did he make and worship?', 'Molten images for Baalim', 'A golden calf like Jeroboam made', 'An idol of Dagon the Philistine god', 'A bronze serpent like Moses made', 'a', '2 Chronicles 28:2 — "For he walked in the ways of the kings of Israel, and made also molten images for Baalim."'),
('2 Chronicles', 28, 'kids', 2, 'Who was the prophet that stopped the Israelite soldiers from making slaves of the people of Judah they had captured?', 'Oded', 'Isaiah', 'Micah', 'Hosea', 'a', '2 Chronicles 28:9 — "But a prophet of the LORD was there, whose name was Oded: and he went out before the host that came to Samaria, and said unto them, Behold, because the LORD God of your fathers was wroth with Judah, he hath delivered them into your hand."'),
('2 Chronicles', 28, 'kids', 3, 'When Ahaz was in trouble, who did he ask for help instead of trusting God?', 'The kings of Assyria', 'The Pharaoh of Egypt', 'The king of Babylon', 'The king of Tyre', 'a', '2 Chronicles 28:16 — "At that time did king Ahaz send unto the kings of Assyria to help him."'),
-- Teens
('2 Chronicles', 28, 'teens', 1, 'What terrible sin did Ahaz commit involving his own children?', 'He burnt his children in the fire, after the abominations of the heathen', 'He sold his children into slavery to Phoenicia', 'He dedicated his sons to idol priests as servants', 'He forced his children to marry foreign kings'' daughters', 'a', '2 Chronicles 28:3 — "Moreover he burnt incense in the valley of the son of Hinnom, and burnt his children in the fire, after the abominations of the heathen whom the LORD had cast out before the children of Israel."'),
('2 Chronicles', 28, 'teens', 2, 'By how many men did Israel smite Judah in one day during the Syro-Ephraimite war?', 'A hundred and twenty thousand valiant men in one day', 'Fifty thousand in the first battle', 'Two hundred thousand over three days', 'Thirty thousand in a single ambush', 'a', '2 Chronicles 28:6 — "For Pekah the son of Remaliah slew in Judah an hundred and twenty thousand in one day, which were all valiant men; because they had forsaken the LORD God of their fathers."'),
('2 Chronicles', 28, 'teens', 3, 'What did the Israelite men of Ephraim do after Oded the prophet rebuked them about the captives?', 'They rose up, took the captives, clothed them from the spoil, and brought them to Jericho, the city of palm trees', 'They set the captives free in the wilderness', 'They returned the captives to Jerusalem immediately', 'They divided the captives among the Levite cities', 'a', '2 Chronicles 28:14-15 — "So the armed men left the captives and the spoil before the princes and all the congregation. And the men which were expressed by name rose up, and took the captives, and with the spoil clothed all that were naked among them...and brought them to Jericho."'),
('2 Chronicles', 28, 'teens', 4, 'What foreign powers attacked Judah simultaneously while Ahaz was under pressure from Israel and Syria?', 'The Edomites smote Judah and carried away captives, and the Philistines invaded the cities of the low country and the south of Judah', 'The Moabites and Ammonites invaded from the east', 'The Egyptians raided the Negev', 'The Assyrians attacked Jerusalem directly', 'a', '2 Chronicles 28:17-18 — "For again the Edomites had come and smitten Judah, and carried away captives. The Philistines also had invaded the cities of the low country, and of the south of Judah."'),
('2 Chronicles', 28, 'teens', 5, 'What did Ahaz do with the treasures of the temple when he appealed to Assyria for help?', 'He took a portion out of the house of the LORD, and out of the house of the king, and of the princes, and gave it to the king of Assyria — but he helped him not', 'He melted down all the bronze furnishings', 'He offered the temple itself as a gift to Assyria', 'He transferred the ark to Assyria as a pledge', 'a', '2 Chronicles 28:21 — "For Ahaz took away a portion out of the house of the LORD, and out of the house of the king, and of the princes, and gave it unto the king of Assyria: but he helped him not."'),
-- Adults
('2 Chronicles', 28, 'adults', 1, 'What specific theological reason does the Chronicler give for Judah''s defeat by Israel, and what does this reveal about his view of military outcomes?', 'Because they had forsaken the LORD God of their fathers; showing that military defeat is always the consequence of spiritual apostasy in the Chronicler''s framework', 'The defeat was due to Ahaz''s inferior military tactics', 'The defeat was God''s will to reunite the kingdom', 'The defeat proved Israel''s army was always stronger', 'a', '2 Chronicles 28:6 — "For Pekah...slew in Judah an hundred and twenty thousand in one day, which were all valiant men; because they had forsaken the LORD God of their fathers."'),
('2 Chronicles', 28, 'adults', 2, 'What was the name of the Israelite who killed the king''s son, the governor of the house, and the king''s second in command in the battle against Judah?', 'Zichri, a mighty man of Ephraim, killed Maaseiah the king''s son, and Azrikam and Elkanah that was next to the king', 'Pekah the king himself killed all three', 'Oded the prophet''s son killed them in battle', 'An unnamed captain from the tribe of Dan', 'a', '2 Chronicles 28:7 — "And Zichri, a mighty man of Ephraim, slew Maaseiah the king''s son, and Azrikam the governor of the house, and Elkanah that was next to the king."'),
('2 Chronicles', 28, 'adults', 3, 'What was the key argument Oded used to persuade Israel not to enslave the captives of Judah?', 'That Israel themselves had sins against God, and if they enslaved Judah they would add to their own trespass, and there was fierce wrath against Israel already', 'That it was illegal under Mosaic law to enslave kinsmen', 'That the captives were too weak to be useful as slaves', 'That the surrounding nations would mock Israel for enslaving brothers', 'a', '2 Chronicles 28:10-11 — "And now ye purpose to keep under the children of Judah and Jerusalem for bondmen and bondwomen unto you: but are there not with you, even with you, sins against the LORD your God? Now hear me therefore, and deliver the captives again."'),
('2 Chronicles', 28, 'adults', 4, 'What does the Chronicler''s account of Ahaz''s response to trouble reveal about the spiritual logic of his reign?', 'In his time of distress he trespassed yet more against the LORD, showing that hardship without repentance leads to deeper apostasy rather than return to God', 'Ahaz was repentant but did not know how to seek God properly', 'Ahaz''s advisors prevented him from turning to the LORD', 'Ahaz sought God but God refused to hear him because of Manasseh''s sins', 'a', '2 Chronicles 28:22 — "And in the time of his distress did he trespass yet more against the LORD: this is that king Ahaz."'),
('2 Chronicles', 28, 'adults', 5, 'What did Ahaz do with the altars of the gods of Damascus, and what was his stated rationale?', 'He sacrificed to the gods of Damascus which smote him, saying because the gods of the kings of Syria help them I will sacrifice to them that they may help me', 'He destroyed the Damascene altars to prove his loyalty to God', 'He sent the altars to Assyria as tribute', 'He set up the altars as trophies of his victory', 'a', '2 Chronicles 28:23 — "For he sacrificed unto the gods of Damascus, which smote him: and he said, Because the gods of the kings of Syria help them, therefore will I sacrifice to them, that they may help me."'),
('2 Chronicles', 28, 'adults', 6, 'What did Ahaz do to the vessels of the house of God, the temple doors, and the altars at the end of his reign?', 'He cut in pieces the vessels of the house of God, shut up the doors of the house of the LORD, and made altars in every corner of Jerusalem and high places in every city of Judah', 'He melted the vessels to make coins', 'He sent the vessels to Assyria as tribute', 'He buried the holy vessels to protect them from the Assyrians', 'a', '2 Chronicles 28:24-25 — "And Ahaz gathered together the vessels of the house of God, and cut in pieces the vessels...and he shut up the doors of the house of the LORD...And in every several city of Judah he made high places to burn incense unto other gods."'),
('2 Chronicles', 28, 'adults', 7, 'What princes of Ephraim by name stood against those returning from battle to insist the captives be released?', 'Azariah the son of Johanan, Berechiah the son of Meshillemoth, Jehizkiah the son of Shallum, and Amasa the son of Hadlai', 'Oded and his four sons', 'The chief Levites of Samaria', 'The elders of the gate of Samaria', 'a', '2 Chronicles 28:12 — "Then certain of the heads of the children of Ephraim, Azariah the son of Johanan, Berechiah the son of Meshillemoth, and Jehizkiah the son of Shallum, and Amasa the son of Hadlai, stood up against them that came from the war."'),
('2 Chronicles', 28, 'adults', 8, 'How many cities did the Philistines take from Judah during Ahaz''s reign, and what does the Chronicler say was the cause?', 'They took Beth-shemesh, Aijalon, Gederoth, Shocho, Timnah, Gimzo, and their villages; the LORD brought Judah low because of Ahaz king of Israel who made Judah naked and transgressed sore', 'They took only three border cities', 'They took twenty cities and enslaved the population', 'They took Lachish and the surrounding towns only', 'a', '2 Chronicles 28:18-19 — "The Philistines also had invaded the cities of the low country...For the LORD brought Judah low because of Ahaz king of Israel; for he made Judah naked, and transgressed sore against the LORD."');

-- ═══ 2 Chronicles Chapter 29 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 29, 'kids', 1, 'King Hezekiah opened and repaired what building in his first year as king?', 'The doors of the house of the LORD', 'The city walls of Jerusalem', 'The water channels of Siloam', 'The royal palace', 'a', '2 Chronicles 29:3 — "He in the first year of his reign, in the first month, opened the doors of the house of the LORD, and repaired them."'),
('2 Chronicles', 29, 'kids', 2, 'Who did Hezekiah gather together to help cleanse the temple?', 'The priests and the Levites', 'The soldiers and the elders', 'The prophets and the scribes', 'The kings and the princes', 'a', '2 Chronicles 29:4 — "And he brought in the priests and the Levites, and gathered them together into the east street."'),
('2 Chronicles', 29, 'kids', 3, 'After the temple was cleansed, what did Hezekiah command the Levites to do with musical instruments?', 'To praise the LORD with the words of David and Asaph', 'To teach the people to sing new songs', 'To play music for the king''s coronation', 'To make new instruments from cedar wood', 'a', '2 Chronicles 29:30 — "Moreover Hezekiah the king and the princes commanded the Levites to sing praise unto the LORD with the words of David, and of Asaph the seer."'),
-- Teens
('2 Chronicles', 29, 'teens', 1, 'What did Hezekiah say to the Levites about why Judah was in its current miserable condition?', 'Our fathers have trespassed and done evil in God''s eyes, forsaken him, turned their faces away, shut the temple doors, and quenched the lamps — therefore the wrath of the LORD is upon Judah', 'Our fathers were defeated in battle because they did not train soldiers well', 'Our fathers offended the Assyrian king and brought his army upon us', 'Our fathers failed to pay tithes and God removed his protection', 'a', '2 Chronicles 29:6-8 — "For our fathers have trespassed, and done that which was evil in the eyes of the LORD our God, and have forsaken him...Wherefore the wrath of the LORD was upon Judah and Jerusalem."'),
('2 Chronicles', 29, 'teens', 2, 'How many days did it take the priests and Levites to sanctify the house of the LORD and carry the uncleanness out?', 'Eight days sanctifying the porch and the house, then eight more days the altar and the holy vessels — sixteen days total', 'Seven days as commanded in the law of Moses', 'Three days for the inner sanctuary', 'One month for the entire temple compound', 'a', '2 Chronicles 29:17 — "Now they began on the first day of the first month to sanctify, and on the eighth day of the month came they to the porch of the LORD: so they sanctified the house of the LORD in eight days; and in the sixteenth day of the first month they made an end."'),
('2 Chronicles', 29, 'teens', 3, 'What did Hezekiah say was his purpose in making a covenant with the LORD?', 'That the fierce wrath of the LORD might turn away from Israel', 'To secure victory against Assyria', 'To obtain God''s blessing on the harvest', 'To establish his dynasty on the throne forever', 'a', '2 Chronicles 29:10 — "Now it is in mine heart to make a covenant with the LORD God of Israel, that his fierce wrath may turn away from us."'),
('2 Chronicles', 29, 'teens', 4, 'How many burnt offerings did the congregation bring for the dedication, and what was special about their number?', 'Seven bullocks, seven rams, seven lambs, seven he goats as a sin offering — the number seven for each type', 'Twelve of each type representing the twelve tribes', 'A hundred of each type showing great abundance', 'One for each Levite who served in the temple', 'a', '2 Chronicles 29:21 — "And they brought seven bullocks, and seven rams, and seven lambs, and seven he goats, for a sin offering for the kingdom, and for the sanctuary, and for Judah."'),
('2 Chronicles', 29, 'teens', 5, 'What did all the congregation do when the burnt offering began and the Levites sang?', 'They bowed themselves and worshipped, and the singers sang and the trumpeters sounded', 'They shouted with a loud voice and ran to the altar', 'They prostrated themselves silently before the holy place', 'They returned to their homes to celebrate the feast', 'a', '2 Chronicles 29:28 — "And all the congregation worshipped, and the singers sang, and the trumpeters sounded: and all this continued until the burnt offering was finished."'),
-- Adults
('2 Chronicles', 29, 'adults', 1, 'What does Hezekiah''s declaration "it is in mine heart" reveal about the Chronicler''s view of true reform?', 'It is fundamentally personal — a king''s deliberate inward decision to seek God precedes and drives institutional reform, as the Chronicler shows throughout Chronicles', 'It is primarily institutional — the temple system must be restored before personal faith can function', 'It is mainly legal — correct observance of the law automatically produces revival', 'It is political — Hezekiah wanted to consolidate power through the temple establishment', 'a', '2 Chronicles 29:10 — "Now it is in mine heart to make a covenant with the LORD God of Israel," placing personal resolve at the root of national renewal.'),
('2 Chronicles', 29, 'adults', 2, 'What specific unclean items did the priests carry out of the sanctuary, and where did the Levites take them?', 'All the uncleanness found in the temple of the LORD into the court, and the Levites carried it out to the brook Kidron — a place associated with disposing of idolatrous objects in other reformations', 'They burned everything on the altar of burnt offering', 'They buried unclean items under the temple mount', 'They threw them into the Dead Sea', 'a', '2 Chronicles 29:16 — "And the priests went into the inner part of the house of the LORD, to cleanse it, and brought out all the uncleanness...And the Levites took it, to carry it out abroad into the brook Kidron."'),
('2 Chronicles', 29, 'adults', 3, 'What was the role of the Levites when there were not enough sanctified priests, and what commendation does the text give them?', 'The Levites killed the sin offerings because there were not enough sanctified priests — the Levites were more upright in heart to sanctify themselves than the priests', 'The Levites composed new psalms while the priests performed the sacrifices', 'The Levites taught the people while the priests played music', 'The Levites received the offering money and the priests distributed it', 'a', '2 Chronicles 29:34 — "But the priests were too few...wherefore their brethren the Levites did help them...for the Levites were more upright in heart to sanctify themselves than the priests."'),
('2 Chronicles', 29, 'adults', 4, 'How many bulls, rams, lambs, oxen, and sheep were offered in the great burnt offering and consecrated things?', 'Seventy bullocks, a hundred rams, two hundred lambs for burnt offering; six hundred oxen and three thousand sheep for holy things', 'Seven bullocks, seven rams, seven lambs, seven goats only', 'A hundred bulls and a thousand lambs', 'Twelve of each animal representing the twelve tribes', 'a', '2 Chronicles 29:32-33 — "And the number of the burnt offerings, which the congregation brought, was threescore and ten bullocks, an hundred rams, and two hundred lambs...And the consecrated things were six hundred oxen and three thousand sheep."'),
('2 Chronicles', 29, 'adults', 5, 'What instruments did Hezekiah command the Levites to use, and what was their scriptural precedent?', 'Cymbals, psalteries, and harps according to the commandment of David and Gad and Nathan the king''s prophet, for the commandment was by the LORD through his prophets', 'Only the trumpets as prescribed in Numbers', 'Harps and lyres only as David had used', 'Seven trumpets as used at Jericho', 'a', '2 Chronicles 29:25 — "And he set the Levites in the house of the LORD with cymbals, with psalteries, and with harps, according to the commandment of David, and of Gad the king''s seer, and Nathan the prophet: for so was the commandment of the LORD by his prophets."'),
('2 Chronicles', 29, 'adults', 6, 'What theological significance does Hezekiah''s speech attribute to the exile of their kinsmen?', 'It was God''s judgment — a sword, captivity, spoil, and derision — because the trespass of their fathers who forsook God brought the wrath of the LORD upon Judah and Jerusalem', 'It was a natural consequence of political weakness', 'It was a test to purify the faithful remnant', 'It was caused by the sins of foreign nations against Israel', 'a', '2 Chronicles 29:8-9 — "Wherefore the wrath of the LORD was upon Judah and Jerusalem, and he hath delivered them to trouble, to astonishment, and to hissing, as ye see with your eyes. For, lo, our fathers have fallen by the sword."'),
('2 Chronicles', 29, 'adults', 7, 'What phrase does Hezekiah use to describe the temple''s proper function, and what does this reveal about his theology of the sanctuary?', 'He calls it a place to stand before God, to serve him, and to burn incense — showing the temple''s purpose is ongoing ministry and intercession on behalf of the nation', 'He calls it a treasury for the nation''s wealth', 'He calls it a palace for the king of heaven', 'He calls it a school for teaching the law', 'a', '2 Chronicles 29:11 — "My sons, be not now negligent: for the LORD hath chosen you to stand before him, to serve him, and that ye should minister unto him, and burn incense."'),
('2 Chronicles', 29, 'adults', 8, 'What was the immediate congregational response to the rededication, and what does the Chronicler emphasize about the speed of the reform?', 'All the congregation rejoiced, and Hezekiah rejoiced because the thing was done suddenly — God had prepared the people for such rapid transformation', 'The people celebrated for seven days before the rededication was complete', 'The congregation was divided and some refused to participate', 'Only the priests and Levites rejoiced while the people waited outside', 'a', '2 Chronicles 29:36 — "And Hezekiah rejoiced, and all the people, that God had prepared the people: for the thing was done suddenly."');

-- ═══ 2 Chronicles Chapter 30 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 30, 'kids', 1, 'What special feast did Hezekiah invite all Israel and Judah to celebrate in Jerusalem?', 'The passover unto the LORD God of Israel', 'The feast of tabernacles', 'The feast of first fruits', 'The feast of trumpets', 'a', '2 Chronicles 30:1 — "And Hezekiah sent to all Israel and Judah, and wrote letters also to Ephraim and Manasseh, that they should come to the house of the LORD at Jerusalem, to keep the passover unto the LORD God of Israel."'),
('2 Chronicles', 30, 'kids', 2, 'Why was the Passover held in the second month instead of the first month?', 'Because the priests had not sanctified themselves in time and the people had not gathered to Jerusalem', 'Because the king was sick and could not attend', 'Because the temple was not yet cleaned', 'Because it rained heavily in the first month', 'a', '2 Chronicles 30:3 — "For they could not keep it at that time, because the priests had not sanctified themselves sufficiently, neither had the people gathered themselves together to Jerusalem."'),
('2 Chronicles', 30, 'kids', 3, 'How many extra days did the people celebrate because they were so happy?', 'Another seven days they kept it with gladness', 'Three more days', 'Fourteen more days', 'One more day', 'a', '2 Chronicles 30:23 — "And the whole assembly took counsel to keep other seven days: and they kept other seven days with gladness."'),
-- Teens
('2 Chronicles', 30, 'teens', 1, 'What did the couriers proclaim as they went through Israel with Hezekiah''s letters?', 'Ye children of Israel, turn again unto the LORD God of Abraham, Isaac, and Israel, and he will return to the remnant of you that are escaped out of the hand of the kings of Assyria', 'Come to Jerusalem and pay your taxes to King Hezekiah', 'The temple has been rebuilt — come and see its glory', 'Hezekiah has defeated Assyria — come celebrate the victory', 'a', '2 Chronicles 30:6 — "So the posts went with the letters from the king and his princes throughout all Israel and Judah...saying, Ye children of Israel, turn again unto the LORD God of Abraham, Isaac, and Israel."'),
('2 Chronicles', 30, 'teens', 2, 'How did most of the northern tribes respond to the invitation couriers?', 'They laughed them to scorn and mocked them', 'They gladly received the invitation and came to Jerusalem', 'They sent a message asking for more time to prepare', 'They consulted their own priests and refused politely', 'a', '2 Chronicles 30:10 — "So the posts passed from city to city through the country of Ephraim and Manasseh even unto Zebulun: but they laughed them to scorn, and mocked them."'),
('2 Chronicles', 30, 'teens', 3, 'What did Hezekiah pray for the many people who ate the Passover without the required purification?', 'He prayed that the good LORD would pardon every one that prepareth his heart to seek God, though not purified according to the purification of the sanctuary', 'He asked the priests to perform purification ceremonies overnight', 'He requested that God delay the feast another month', 'He offered extra sin offerings on their behalf', 'a', '2 Chronicles 30:18-19 — "But Hezekiah prayed for them, saying, The good LORD pardon every one That prepareth his heart to seek God, the LORD God of his fathers, though he be not cleansed according to the purification of the sanctuary."'),
('2 Chronicles', 30, 'teens', 4, 'Which northern tribes actually humbled themselves and came to Jerusalem for the Passover?', 'Divers of Asher, Manasseh, and Zebulun humbled themselves and came to Jerusalem', 'Only the tribe of Benjamin came from the north', 'The tribes of Dan and Naphtali came', 'None from the north came — only Judah attended', 'a', '2 Chronicles 30:11 — "Nevertheless divers of Asher and Manasseh and of Zebulun humbled themselves, and came to Jerusalem."'),
('2 Chronicles', 30, 'teens', 5, 'What did the people do to the altars and incense altars in Jerusalem during the feast?', 'They arose and took away the altars that were in Jerusalem, and all the altars for incense, and cast them into the brook Kidron', 'They left them for the priests to dismantle later', 'They burned them with fire outside the city', 'They buried them under the temple foundations', 'a', '2 Chronicles 30:14 — "And they arose and took away the altars that were in Jerusalem, and all the altars for incense took they away, and cast them into the brook Kidron."'),
-- Adults
('2 Chronicles', 30, 'adults', 1, 'What does the Chronicler''s description of Hezekiah''s Passover as unprecedented since Solomon reveal about its theological significance?', 'That Hezekiah''s reform represented a restoration of the Solomonic ideal — a united Israel gathered at the Jerusalem sanctuary — making it the greatest act of national reunification since the divided kingdom', 'That Hezekiah was greater than Solomon in all ways', 'That previous Passovers had been celebrated incorrectly', 'That the northern tribes had never celebrated Passover', 'a', '2 Chronicles 30:26 — "So there was great joy in Jerusalem: for since the time of Solomon the son of David king of Israel there was not the like in Jerusalem."'),
('2 Chronicles', 30, 'adults', 2, 'What was the theological argument in Hezekiah''s letter for why even the northern remnant should attend the Passover?', 'That if they returned to the LORD, their brethren and children would find compassion before their captors and the LORD — gracious and merciful — would not turn away if they returned to him', 'That Hezekiah as king of Judah had legal authority over all twelve tribes', 'That the temple was the only valid place of worship and ignoring it was sin', 'That a political alliance with Judah was their best protection against Assyria', 'a', '2 Chronicles 30:9 — "For if ye turn again unto the LORD...then your brethren and your children shall find compassion before them that lead them captive...for the LORD your God is gracious and merciful, and will not turn away his face from you, if ye return unto him."'),
('2 Chronicles', 30, 'adults', 3, 'How does God respond to Hezekiah''s prayer for those who ate the Passover without purification, and what principle does this establish?', 'The LORD hearkened to Hezekiah and healed the people — establishing that sincere preparation of heart takes precedence over ritual purity when circumstances prevent full observance', 'God required additional sacrifices before accepting the worship', 'God accepted only those who were properly purified', 'God was silent and no sign was given', 'a', '2 Chronicles 30:20 — "And the LORD hearkened to Hezekiah, and healed the people."'),
('2 Chronicles', 30, 'adults', 4, 'What is the significance of the great assembly''s spontaneous decision to keep an additional seven days of celebration?', 'It shows the genuineness of the spiritual revival — the people themselves desired to extend their worship without royal compulsion, supplied joyfully by Hezekiah and his officials', 'It shows Hezekiah had planned the extended feast from the beginning', 'It shows the people were reluctant to return to their work', 'It shows the priests needed extra time to finish the sacrifices', 'a', '2 Chronicles 30:23-24 — "And the whole assembly took counsel to keep other seven days: and they kept other seven days with gladness. For Hezekiah king of Judah did give to the congregation a thousand bullocks and seven thousand sheep."'),
('2 Chronicles', 30, 'adults', 5, 'What did Hezekiah and the princes contribute to sustain the extended seven-day feast?', 'Hezekiah gave a thousand bullocks and seven thousand sheep, and the princes gave a thousand bullocks and ten thousand sheep, and a great number of priests sanctified themselves', 'Only Hezekiah contributed out of the royal treasury', 'The Levites gave from the tithe storehouses', 'Wealthy merchants donated on behalf of the congregation', 'a', '2 Chronicles 30:24 — "For Hezekiah king of Judah did give to the congregation a thousand bullocks and seven thousand sheep; and the princes gave to the congregation a thousand bullocks and ten thousand sheep."'),
('2 Chronicles', 30, 'adults', 6, 'What was the role of the Levites in teaching the people during the feast, and how does this show the dual function of temple worship?', 'The Levites praised the LORD day by day, and Hezekiah spoke comfortably to all the Levites that taught the good knowledge of the LORD — showing worship and instruction as inseparable', 'The Levites only performed sacrifices and did not teach', 'Teaching happened separately in the synagogues', 'Only the high priest addressed the people', 'a', '2 Chronicles 30:22 — "And Hezekiah spake comfortably unto all the Levites that taught the good knowledge of the LORD: and they did eat throughout the feast seven days, offering peace offerings."'),
('2 Chronicles', 30, 'adults', 7, 'How does the Chronicler describe the prayer during the feast ascending to God?', 'Their voice was heard and their prayer came up to his holy dwelling place, even unto heaven — showing that corporate worship of a reunited people has special power before God', 'Only Hezekiah''s private prayer was recorded as heard', 'The priests'' formal prayers alone ascended to heaven', 'The people prayed individually and God heard each separately', 'a', '2 Chronicles 30:27 — "Then the priests the Levites arose and blessed the people: and their voice was heard, and their prayer came up to his holy dwelling place, even unto heaven."'),
('2 Chronicles', 30, 'adults', 8, 'What does the Passover''s celebration in the second month rather than the first month reveal about the relationship between law and grace in Chronicles?', 'That God''s mercy allows legitimate adjustments to ritual law when sincere repentance and seeking of God motivates the participants — the spirit of the law can fulfil its intent even with procedural variation', 'That the Mosaic law was no longer binding after the division of the kingdom', 'That Hezekiah had authority to rewrite the law as king', 'That the second month Passover was an entirely different feast', 'a', '2 Chronicles 30:2-3 — "For the king had taken counsel...to keep the passover in the second month. For they could not keep it at that time, because the priests had not sanctified themselves," showing pastoral accommodation within covenant faithfulness.');

-- ═══ 2 Chronicles Chapter 31 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 31, 'kids', 1, 'After the feast, what did the people break down and destroy throughout Israel and Judah?', 'The images and the groves and the high places and the altars', 'The walls of foreign cities', 'The houses of idol priests', 'The bronze gates of the cities', 'a', '2 Chronicles 31:1 — "Now when all this was finished, all Israel that were present went out to the cities of Judah, and brake the images in pieces, and cut down the groves, and threw down the high places and the altars out of all Judah and Benjamin."'),
('2 Chronicles', 31, 'kids', 2, 'What did Hezekiah ask the people to bring to support the priests and Levites?', 'The portion of the priests and the Levites, and the firstfruits and tithes', 'Silver and gold for rebuilding the temple', 'Animals for daily burnt offerings', 'Cedar wood for new temple furniture', 'a', '2 Chronicles 31:4 — "Moreover he commanded the people that dwelt in Jerusalem to give the portion of the priests and the Levites, that they might be encouraged in the law of the LORD."'),
('2 Chronicles', 31, 'kids', 3, 'What was Hezekiah said to do in every work for the house of God and in the law?', 'He did it with all his heart, and prospered', 'He was the wisest king since Solomon', 'He was the most generous king who ever lived', 'He was a great warrior who never lost a battle', 'a', '2 Chronicles 31:21 — "And in every work that he began in the service of the house of God, and in the law, and in the commandments, to seek his God, he did it with all his heart, and prospered."'),
-- Teens
('2 Chronicles', 31, 'teens', 1, 'How did Hezekiah reorganize the priests and Levites regarding their duties?', 'He appointed the courses of the priests and Levites after their courses, every man according to his service, for burnt offerings and peace offerings, to minister and to give thanks and to praise', 'He reduced the number of Levites to save money', 'He assigned the Levites only to teaching and not to sacrifice', 'He gave the priests roles in civil government', 'a', '2 Chronicles 31:2 — "And Hezekiah appointed the courses of the priests and the Levites after their courses, every man according to his service, the priests and Levites for burnt offerings and for peace offerings, to minister, and to give thanks, and to praise."'),
('2 Chronicles', 31, 'teens', 2, 'What did the people bring in abundance after Hezekiah''s command about tithes?', 'The firstfruits of corn, wine, oil, honey, and all the increase of the field, and the tithe of all things, laid in heaps', 'Only a small portion because of the harvest failure', 'Exactly the legal minimum required by Moses', 'Silver equivalent to a tithe of all produce', 'a', '2 Chronicles 31:5 — "And as soon as the commandment came abroad, the children of Israel brought in abundance the firstfruits of corn, wine, and oil, and honey, and of all the increase of the field."'),
('2 Chronicles', 31, 'teens', 3, 'Who was put in charge of the chambers where the contributions and tithes were stored?', 'Cononiah the Levite was ruler, and Shimei his brother was the next', 'Azariah the chief priest oversaw all storerooms', 'Hezekiah''s personal treasurer controlled the storerooms', 'The elders of each tribe managed their own storerooms', 'a', '2 Chronicles 31:12-13 — "And brought in the offerings and the tithes and the dedicated things faithfully: over which Cononiah the Levite was ruler, and Shimei his brother was the next."'),
('2 Chronicles', 31, 'teens', 4, 'What did Azariah the chief priest tell Hezekiah when he asked about the heaps of firstfruits?', 'Since the people began to bring the offerings into the house of the LORD, we have had enough to eat and have left plenty — for the LORD hath blessed his people; and that which is left is this great store', 'He said the storerooms were nearly empty and more was needed', 'He said the Levites had been keeping too large a share for themselves', 'He said the heaps were from three years of accumulated tithes', 'a', '2 Chronicles 31:10 — "And Azariah the chief priest of the house of Zadok answered him, and said, Since the people began to bring the offerings into the house of the LORD, we have had enough to eat, and have left plenty: for the LORD hath blessed his people."'),
('2 Chronicles', 31, 'teens', 5, 'Who received portions from the tithes besides the male Levites on duty?', 'All males from three years old and upward, and all that were reckoned by genealogy among the Levites — their sons and daughters', 'Only the Levites themselves, not their families', 'Only adult male Levites on active duty', 'Levites in the cities who farmed their own land', 'a', '2 Chronicles 31:16-17 — "Beside their genealogy of males, from three years old and upward, even unto every one that entereth into the house of the LORD...And to the genealogy of the Levites."'),
-- Adults
('2 Chronicles', 31, 'adults', 1, 'What does the thoroughness of the destruction of high places in verse 1 — covering even Ephraim and Manasseh — reveal about Hezekiah''s reform?', 'It reveals Hezekiah attempted a pan-Israelite reform reaching into the former northern kingdom, aligning with his Passover invitation and showing his vision of a reunited covenant people', 'It reveals he had political ambitions over the north', 'It reveals the high places in the north were particularly offensive to Judeans', 'It reveals the northern tribes had invited Judean forces to help them', 'a', '2 Chronicles 31:1 — "All Israel...went out to the cities of Judah, and brake the images in pieces...throughout all Judah and Benjamin, in Ephraim also and Manasseh."'),
('2 Chronicles', 31, 'adults', 2, 'What does the detail that Hezekiah gave from his own possessions for the morning and evening burnt offerings show about his reform?', 'It shows he put his own wealth behind the worship restoration rather than merely commanding others — true leadership requires personal sacrifice', 'It shows he was wealthy beyond measure and could afford any expense', 'It shows the temple treasury had been completely emptied by Ahaz', 'It shows he did not trust the Levites to manage funds properly', 'a', '2 Chronicles 31:3 — "He appointed also the king''s portion of his substance for the burnt offerings, to wit, for the morning and evening burnt offerings, and the burnt offerings for the sabbaths, and for the new moons, and for the set feasts, as it is written in the law of the LORD."'),
('2 Chronicles', 31, 'adults', 3, 'How does the Chronicler''s emphasis on genealogy in the distribution of Levitical provisions reflect a broader concern in Chronicles?', 'Chronicles repeatedly emphasizes genealogy as the basis of legitimate service and inheritance — proper genealogical registration ensured correct distribution and prevented fraud', 'Genealogy was purely administrative with no theological significance', 'Genealogy was only relevant for the Davidic dynasty', 'Genealogy was a recent innovation introduced by Hezekiah', 'a', '2 Chronicles 31:17-18 — "Both to the genealogy of the priests by the house of their fathers, and the Levites from twenty years old and upward...And to the genealogy of all their little ones, their wives, and their sons and their daughters."'),
('2 Chronicles', 31, 'adults', 4, 'What officials were appointed to administer the chambers and the distribution of tithes under Cononiah?', 'Hezekiah commanded to prepare chambers in the house of the LORD; Cononiah the Levite ruled over them with Shimei his brother as deputy, and ten others appointed under him', 'The city elders distributed portions without appointed officers', 'The chief priest alone distributed from Jerusalem', 'The princes of each tribe managed distribution in their territory', 'a', '2 Chronicles 31:11-13 — "Then Hezekiah commanded to prepare chambers in the house of the LORD...And brought in the offerings...faithfully: over which Cononiah the Levite was ruler, and Shimei his brother was the next. And Jehiel...and Azariah...and Nahath, and Asahel, and Jerimoth...were overseers."'),
('2 Chronicles', 31, 'adults', 5, 'What is the significance of the Chronicler noting that Hezekiah did this "in every city of Judah" and not just Jerusalem?', 'It shows his reform was not merely a Jerusalem phenomenon but a genuine national transformation reaching every part of the kingdom — thoroughness the Chronicler prizes in true revival', 'It shows Hezekiah needed tax revenue from every city', 'It shows the Levites were spread too thinly across the land', 'It shows the law required temple cities in every region', 'a', '2 Chronicles 31:19 — "Also of the sons of Aaron the priests, which were in the fields of the suburbs of their cities, in every several city, the men that were expressed by name, to give portions to all the males among the priests."'),
('2 Chronicles', 31, 'adults', 6, 'What is the Chronicler''s overall summary verdict on Hezekiah, and what three qualities does it cite?', 'He wrought that which was good and right and truth before the LORD his God — combining moral goodness, covenant righteousness, and fidelity to truth as a triple standard', 'He was the greatest military king since David', 'He was faithful in wealth but not in worship', 'He was good in his youth but failed in old age', 'a', '2 Chronicles 31:20 — "And thus did Hezekiah throughout all Judah, and wrought that which was good and right and truth before the LORD his God."'),
('2 Chronicles', 31, 'adults', 7, 'How does the abundance of the tithes function theologically in the Chronicler''s narrative of chapter 31?', 'The overflowing heaps demonstrate the principle that seeking God first leads to material abundance — a direct application of the covenant blessing principle rooted in Deuteronomy', 'The tithes are mentioned only as an administrative detail', 'The abundance shows the people feared punishment for withholding', 'The tithes demonstrate Israel''s superior agriculture compared to surrounding nations', 'a', '2 Chronicles 31:10 — "The LORD hath blessed his people; and that which is left is this great store," showing the tithes as evidence of covenant blessing flowing from faithfulness.'),
('2 Chronicles', 31, 'adults', 8, 'What name does the text give to the chief priest of Hezekiah''s time, and to what family line does it connect him?', 'Azariah the chief priest of the house of Zadok — connecting the priesthood to the Zadokite line that had served since Solomon''s dedication of the temple', 'Jehoiada of the line of Aaron', 'Hilkiah the son of Shallum', 'Urijah of the house of Eleazar', 'a', '2 Chronicles 31:10 — "And Azariah the chief priest of the house of Zadok answered him," — the Zadokite line being the priestly family favoured by Solomon at the very start of the temple era.');

-- ═══ 2 Chronicles Chapter 32 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 32, 'kids', 1, 'What great enemy king came to attack Jerusalem in Hezekiah''s days?', 'Sennacherib king of Assyria', 'Nebuchadnezzar king of Babylon', 'Pharaoh Necho of Egypt', 'Tiglath-pileser king of Assyria', 'a', '2 Chronicles 32:1 — "After these things, and the establishment thereof, Sennacherib king of Assyria came, and entered into Judah."'),
('2 Chronicles', 32, 'kids', 2, 'What did God send to destroy the Assyrian army at Jerusalem?', 'An angel who cut off all the mighty men of valour', 'Lightning from heaven', 'A great plague of locusts', 'A flood that swept away the army', 'a', '2 Chronicles 32:21 — "And the LORD sent an angel, which cut off all the mighty men of valour, and the leaders and captains in the camp of the king of Assyria."'),
('2 Chronicles', 32, 'kids', 3, 'After God delivered Jerusalem, Hezekiah became proud. What did he do to make things right?', 'He humbled himself for the pride of his heart, so the wrath of the LORD came not upon them', 'He offered a hundred bulls as a sacrifice', 'He gave all his wealth to the temple treasury', 'He asked Isaiah to pray for him', 'a', '2 Chronicles 32:26 — "Notwithstanding Hezekiah humbled himself for the pride of his heart, both he and the inhabitants of Jerusalem, so that the wrath of the LORD came not upon them in the days of Hezekiah."'),
-- Teens
('2 Chronicles', 32, 'teens', 1, 'What water project did Hezekiah carry out to deny the Assyrian army access to water?', 'He stopped all the fountains and the brook that ran through the midst of the land, saying why should the kings of Assyria find much water?', 'He built a great dam across the Jordan', 'He poisoned the wells outside Jerusalem', 'He diverted a canal into Jerusalem from the north', 'a', '2 Chronicles 32:3-4 — "He took counsel with his princes and his mighty men to stop the waters of the fountains which were without the city...So there was gathered much people together, who stopped all the fountains, and the brook that ran through the midst of the land."'),
('2 Chronicles', 32, 'teens', 2, 'What did Sennacherib''s servants say to the people of Jerusalem about the God of Hezekiah?', 'They spoke against the God of Jerusalem as against the gods of the nations — no god of any nation had delivered his people from Assyria, and neither would the God of Jerusalem', 'They promised riches if the city surrendered peacefully', 'They said Hezekiah had lied to them about God''s power', 'They warned that the Assyrian army was undefeatable', 'a', '2 Chronicles 32:19 — "And they spake against the God of Jerusalem, as against the gods of the people of the earth, which were the work of the hands of man."'),
('2 Chronicles', 32, 'teens', 3, 'What happened to Sennacherib when he returned to Assyria after his defeat at Jerusalem?', 'He went into the house of his god, and some of his own sons smote him there with the sword', 'He died of shame and grief within a year', 'He was deposed by his army commanders', 'He attacked Egypt and was defeated there too', 'a', '2 Chronicles 32:21 — "And he returned with shame of face to his own land. And when he was come into the house of his god, they that came forth of his own bowels slew him there with the sword."'),
('2 Chronicles', 32, 'teens', 4, 'What illness did Hezekiah suffer and what did God do regarding the Babylonian ambassadors who came to inquire?', 'He was sick unto death and God healed him; God left him concerning the Babylonian ambassadors to try him, that he might know all that was in his heart', 'He broke his leg in battle and the prophet healed him', 'He was poisoned by Assyrian spies and recovered miraculously', 'He had a fever and the people fasted three days for him', 'a', '2 Chronicles 32:24,31 — "In those days Hezekiah was sick to the death...Howbeit in the business of the ambassadors of the princes of Babylon...God left him, to try him, that he might know all that was in his heart."'),
('2 Chronicles', 32, 'teens', 5, 'What great wealth and honour did Hezekiah accumulate, showing God''s blessing upon him?', 'He had exceeding much riches and honour, and made treasuries for silver, gold, precious stones, spices, shields, and pleasant jewels, and all nations brought gifts to him', 'He had a powerful army that conquered all surrounding nations', 'He received tribute only from Philistia and Edom', 'He built the largest palace ever seen in Judah', 'a', '2 Chronicles 32:27-28 — "And Hezekiah had exceeding much riches and honour: and he made himself treasuries for silver, and for gold, and for precious stones...stalls for all manner of beasts, and cotes for flocks. Moreover he provided him cities, and possessions of flocks and herds in abundance."'),
-- Adults
('2 Chronicles', 32, 'adults', 1, 'What is the theological significance of the phrase "after these things and the establishment thereof" that opens chapter 32?', 'It signals the Chronicler''s teaching that faithfulness does not exempt one from trial but makes God''s deliverance available — Hezekiah''s reforms were tested by the most severe crisis of his reign', 'It indicates there was a long gap between the reforms and the invasion', 'It shows Sennacherib chose to attack because Hezekiah was weak', 'It is a standard literary formula with no theological meaning', 'a', '2 Chronicles 32:1 — "After these things, and the establishment thereof, Sennacherib king of Assyria came," — the Chronicler places the invasion immediately after the reforms to teach trust under trial.'),
('2 Chronicles', 32, 'adults', 2, 'What speech did Hezekiah give to encourage the people, and what is its theological core?', 'He said be strong and courageous, be not afraid for the king of Assyria — for there be more with us than with him: with him is an arm of flesh, but with us is the LORD our God to help us and to fight our battles', 'He promised victory based on Judah''s superior army', 'He declared he would personally lead the charge and God would follow', 'He ordered everyone to fast and pray without speaking', 'a', '2 Chronicles 32:7-8 — "Be strong and courageous, be not afraid nor dismayed for the king of Assyria...for there be more with us than with him: With him is an arm of flesh; but with us is the LORD our God to help us, and to fight our battles."'),
('2 Chronicles', 32, 'adults', 3, 'What specific claim did Sennacherib''s letter make about the God of Hezekiah compared to the gods of other nations?', 'That the God of Hezekiah was like the gods of the nations destroyed by Assyria — therefore he would not deliver Jerusalem out of his hand', 'That Hezekiah had offended his own God by removing the high places', 'That God had told Sennacherib to destroy Jerusalem', 'That no god had ever successfully defended a besieged city', 'a', '2 Chronicles 32:15 — "Now therefore let not Hezekiah deceive you...for no god of any nation or kingdom was able to deliver his people out of mine hand, and out of the hand of my fathers: how much less shall your God deliver you out of mine hand?"'),
('2 Chronicles', 32, 'adults', 4, 'How did Hezekiah and Isaiah respond to Sennacherib''s blasphemy, combining human action with divine dependence?', 'Hezekiah the king and Isaiah the prophet the son of Amoz prayed and cried to heaven, and God sent an angel — prayer was the human contribution and divine intervention was God''s response', 'Hezekiah relied entirely on his army without prayer', 'Isaiah alone prayed while Hezekiah made military preparations only', 'They appealed to Egypt for military assistance first', 'a', '2 Chronicles 32:20-21 — "And for this cause Hezekiah the king, and the prophet Isaiah the son of Amoz, prayed and cried to heaven. And the LORD sent an angel."'),
('2 Chronicles', 32, 'adults', 5, 'What does the detail that God left Hezekiah "to try him" regarding the Babylonian ambassadors reveal about divine testing in Chronicles?', 'That God withdraws felt presence as a test of whether the heart is truly devoted — prosperity and recovery can become occasions for spiritual failure as much as for gratitude', 'That God was displeased with Hezekiah for receiving foreign ambassadors', 'That the Babylonian embassy was a political trap Hezekiah should have avoided', 'That God was testing whether Hezekiah would share military secrets', 'a', '2 Chronicles 32:31 — "God left him, to try him, that he might know all that was in his heart."'),
('2 Chronicles', 32, 'adults', 6, 'How does the Chronicler handle Hezekiah''s illness and the sign of the sundial compared to the parallel account in Kings?', 'The Chronicler mentions the sign and recovery briefly, directing readers to the vision of Isaiah the prophet for full details — a cross-reference technique showing awareness of other canonical sources', 'The Chronicler gives a longer account than Kings does', 'The Chronicler denies the sundial miracle occurred', 'The Chronicler replaces the sundial with the tunnel as the key miracle', 'a', '2 Chronicles 32:24 — "In those days Hezekiah was sick to the death, and prayed unto the LORD: and he spake unto him, and he gave him a sign," with full details found in Isaiah 38.'),
('2 Chronicles', 32, 'adults', 7, 'What does Hezekiah''s construction of the water conduit to bring Gihon spring water into the city represent strategically and spiritually?', 'It represents preparation and faith working together — he secured the city''s water supply against siege while trusting God, showing that prudent preparation and prayer are complementary not contradictory', 'It shows he trusted engineering more than God', 'It was purely a defensive measure with no spiritual dimension', 'It was completed after the siege as a memorial to God''s deliverance', 'a', '2 Chronicles 32:30 — "This same Hezekiah also stopped the upper watercourse of Gihon, and brought it straight down to the west side of the city of David."'),
('2 Chronicles', 32, 'adults', 8, 'How does the Chronicler''s treatment of Hezekiah''s pride differ from that of Uzziah''s pride, and what does this reveal about repentance?', 'Hezekiah humbled himself so the wrath came not upon them in his days — unlike Uzziah who persisted in pride and was permanently judged; repentance makes the critical difference in the Chronicler''s theology', 'Both were punished equally and permanently', 'Hezekiah''s pride was not as serious as Uzziah''s', 'Hezekiah was never proud — the text is speaking of the people alone', 'a', '2 Chronicles 32:26 — "Notwithstanding Hezekiah humbled himself for the pride of his heart, both he and the inhabitants of Jerusalem, so that the wrath of the LORD came not upon them in the days of Hezekiah."');

-- ═══ 2 Chronicles Chapter 33 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 33, 'kids', 1, 'King Manasseh of Judah did many wicked things. What did he rebuild that Hezekiah had destroyed?', 'The high places', 'The temple', 'The city walls', 'The royal stables', 'a', '2 Chronicles 33:3 — "For he built again the high places which Hezekiah his father had broken down."'),
('2 Chronicles', 33, 'kids', 2, 'Where was Manasseh taken as a prisoner when God judged him?', 'To Babylon', 'To Egypt', 'To Assyria', 'To Philistia', 'a', '2 Chronicles 33:11 — "Wherefore the LORD brought upon them the captains of the host of the king of Assyria, which took Manasseh among the thorns, and bound him with fetters, and carried him to Babylon."'),
('2 Chronicles', 33, 'kids', 3, 'After Manasseh was taken captive, what did he do that made God bring him back to Jerusalem?', 'He humbled himself greatly before the God of his fathers and prayed to God', 'He paid a large ransom to the Assyrians', 'He promised to rebuild the temple', 'He wrote a letter begging God for forgiveness', 'a', '2 Chronicles 33:12-13 — "And when he was in affliction, he besought the LORD his God, and humbled himself greatly before the God of his fathers, And prayed unto him: and he was intreated of him, and heard his supplication, and brought him again to Jerusalem."'),
-- Teens
('2 Chronicles', 33, 'teens', 1, 'What specific abominations did Manasseh commit in the house of God itself?', 'He built altars for all the host of heaven in the two courts of the house of the LORD, and set a carved image in the house of God', 'He burned the temple doors and removed the ark', 'He replaced the golden lampstand with an idol of Baal', 'He turned the inner sanctuary into a treasury for idols', 'a', '2 Chronicles 33:4-5,7 — "Also he built altars in the house of the LORD...And he built altars for all the host of heaven in the two courts of the house of the LORD...And he set a carved image, the idol which he had made, in the house of God."'),
('2 Chronicles', 33, 'teens', 2, 'How does the Chronicler characterize the scale of Manasseh''s wickedness compared to the nations God had destroyed?', 'Manasseh made Judah and the inhabitants of Jerusalem to err and do worse than the heathen whom the LORD had destroyed before the children of Israel', 'Manasseh was only slightly more wicked than Ahaz', 'Manasseh''s sins were fewer than Jeroboam''s', 'Manasseh sinned only in his youth and improved with age', 'a', '2 Chronicles 33:9 — "So Manasseh made Judah and the inhabitants of Jerusalem to err, and to do worse than the heathen, whom the LORD had destroyed before the children of Israel."'),
('2 Chronicles', 33, 'teens', 3, 'After Manasseh''s restoration what did he do to the temple and the city?', 'He took away the strange gods and the idol out of the house of the LORD, repaired the altar of the LORD, commanded Judah to serve the LORD, and built an outer wall for the city of David', 'He demolished the temple and built a new one', 'He restored only the outer courts but kept the inner shrine for idols', 'He gave all the temple gold to the Assyrian king as tribute', 'a', '2 Chronicles 33:15-16 — "And he took away the strange gods, and the idol out of the house of the LORD...And he repaired the altar of the LORD, and sacrificed thereon peace offerings and thank offerings, and commanded Judah to serve the LORD God of Israel."'),
('2 Chronicles', 33, 'teens', 4, 'What was the conduct of Manasseh''s son Amon who succeeded him?', 'Amon trespassed more and more and did evil in the sight of the LORD as his father Manasseh had done, but unlike Manasseh he humbled not himself before the LORD', 'Amon reversed all Manasseh''s evil and followed Hezekiah''s reforms', 'Amon was assassinated before he could do either good or evil', 'Amon ruled wisely but was weak militarily', 'a', '2 Chronicles 33:22-23 — "But he did that which was evil in the sight of the LORD, as did Manasseh his father...And humbled not himself before the LORD, as Manasseh his father had humbled himself; but Amon trespassed more and more."'),
('2 Chronicles', 33, 'teens', 5, 'What was the fate of Amon and who succeeded him?', 'His servants conspired against him and slew him in his own house, and the people of the land made Josiah his son king in his stead', 'Amon died of a sickness after only six months as king', 'The Assyrians captured Amon and he died in captivity', 'Amon was killed in battle against the Philistines', 'a', '2 Chronicles 33:24-25 — "And his servants conspired against him, and slew him in his own house. But the people of the land slew all them that had conspired against king Amon; and the people of the land made Josiah his son king in his stead."'),
-- Adults
('2 Chronicles', 33, 'adults', 1, 'What does the Chronicler''s inclusion of Manasseh''s repentance and restoration reveal about his theological purpose, given that Kings omits this narrative?', 'It demonstrates the Chronicler''s central retribution principle: repentance — even after extreme wickedness — brings divine forgiveness and restoration, showing God''s mercy overrides the severity of sin', 'It shows the Chronicler had access to sources Kings did not have', 'It shows the Chronicler was writing propaganda for a later king', 'It shows Manasseh''s wickedness was exaggerated by the Kings author', 'a', '2 Chronicles 33:13 — "And prayed unto him: and he was intreated of him, and heard his supplication, and brought him again to Jerusalem into his kingdom. Then Manasseh knew that the LORD he was God."'),
('2 Chronicles', 33, 'adults', 2, 'What was the specific mechanism of Manasseh''s capture — how does the text describe the manner of his arrest?', 'The captains of the king of Assyria took Manasseh among the thorns, and bound him with fetters, and carried him to Babylon', 'He surrendered voluntarily to avoid a siege of Jerusalem', 'He was captured in battle while leading his army', 'He was betrayed by his own nobles to the Assyrians', 'a', '2 Chronicles 33:11 — "Wherefore the LORD brought upon them the captains of the host of the king of Assyria, which took Manasseh among the thorns, and bound him with fetters, and carried him to Babylon."'),
('2 Chronicles', 33, 'adults', 3, 'What does "Manasseh knew that the LORD he was God" reveal as the purpose of his suffering, and how does this relate to the Chronicler''s use of affliction?', 'The Chronicler presents affliction as God''s instrument for producing true knowledge of God — captivity broke Manasseh''s idolatrous self-sufficiency and brought him to genuine acknowledgment of the LORD', 'The suffering was purely punitive with no redemptive purpose', 'Manasseh''s knowledge was merely intellectual, not transforming', 'The restoration was a political arrangement with no spiritual significance', 'a', '2 Chronicles 33:13 — "Then Manasseh knew that the LORD he was God," — the climactic statement showing the redemptive purpose of his chastisement.'),
('2 Chronicles', 33, 'adults', 4, 'Why does the Chronicler note that the people still sacrificed in the high places after Manasseh''s restoration, even though his personal repentance was genuine?', 'To show that a leader''s personal reform, even when genuine, cannot fully undo the deep-rooted idolatry his earlier example embedded in the people — leadership''s negative influence outlasts repentance', 'To show Manasseh''s repentance was insincere', 'To show the high places were legal worship sites at this period', 'To show the Levites had failed to teach the people properly', 'a', '2 Chronicles 33:17 — "Nevertheless the people did sacrifice still in the high places, yet unto the LORD their God only."'),
('2 Chronicles', 33, 'adults', 5, 'What building work did the restored Manasseh carry out that showed his changed priorities?', 'He built an outer wall to the city of David on the west side of Gihon in the valley and raised it up to Ophel, and put captains of war in all the fenced cities of Judah', 'He rebuilt the entire temple from the ground up', 'He constructed a new palace for the priests', 'He built forty altars for the LORD throughout Judah', 'a', '2 Chronicles 33:14 — "Now after this he built a wall without the city of David, on the west side of Gihon, in the valley, even to the entering in at the fish gate, and compassed about Ophel, and raised it up a very great height."'),
('2 Chronicles', 33, 'adults', 6, 'What was the source cited for the prayer of Manasseh and the account of his humbling?', 'The words of the seers who spake to him in the name of the LORD God of Israel, written in the book of the kings of Israel; also his prayer is among the sayings of the Hozai', 'Only the general chronicle of Kings', 'The writings of the prophet Micah', 'The records kept by the Levitical priests', 'a', '2 Chronicles 33:18-19 — "Now the rest of the acts of Manasseh, and his prayer unto his God...written in the book of the kings of Israel. His prayer also...behold, they are written among the sayings of the seers."'),
('2 Chronicles', 33, 'adults', 7, 'How old was Manasseh when he began to reign, how long did he reign, and what does this make his reign in terms of length among Judah''s kings?', 'He was twelve years old and reigned fifty-five years in Jerusalem — the longest reign of any king of Judah', 'He was twenty and reigned forty years', 'He was sixteen and reigned forty-five years', 'He was eight and reigned thirty-one years', 'a', '2 Chronicles 33:1 — "Manasseh was twelve years old when he began to reign, and he reigned fifty and five years in Jerusalem," making his the longest reign recorded for any king of Judah.'),
('2 Chronicles', 33, 'adults', 8, 'What does the contrast between Manasseh''s repentance bearing fruit and Amon''s lack of repentance reveal about the Chronicler''s view of inherited religion?', 'It shows that each generation must personally seek God — a father''s genuine repentance cannot substitute for a son''s own turning to God; Amon had the example before him but chose not to follow it', 'It shows that sons always repeat their fathers'' sins', 'It shows that Amon was too young to understand repentance', 'It shows Manasseh''s repentance was not genuine after all', 'a', '2 Chronicles 33:23 — "And humbled not himself before the LORD, as Manasseh his father had humbled himself; but Amon trespassed more and more," — personal accountability before God is non-transferable.');

-- ═══ 2 Chronicles Chapter 34 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 34, 'kids', 1, 'How old was Josiah when he became king?', 'Eight years old', 'Twelve years old', 'Sixteen years old', 'Twenty years old', 'a', '2 Chronicles 34:1 — "Josiah was eight years old when he began to reign, and he reigned in Jerusalem one and thirty years."'),
('2 Chronicles', 34, 'kids', 2, 'What important book was found in the temple when Josiah was repairing it?', 'The book of the law of the LORD given by Moses', 'The book of the prophecies of Isaiah', 'The book of the psalms of David', 'The book of the genealogies of the priests', 'a', '2 Chronicles 34:14-15 — "And when they brought out the money that was brought into the house of the LORD, Hilkiah the priest found a book of the law of the LORD given by Moses. And Hilkiah answered and said to Shaphan the scribe, I have found the book of the law in the house of the LORD."'),
('2 Chronicles', 34, 'kids', 3, 'What did Josiah do when the book of the law was read to him?', 'He rent his clothes because of the wrath of the LORD poured out on them for not keeping the law', 'He had it copied and sent to every city', 'He read it out loud to all the people immediately', 'He placed it in the ark of the covenant', 'a', '2 Chronicles 34:19 — "And it came to pass, when the king had heard the words of the law, that he rent his clothes."'),
-- Teens
('2 Chronicles', 34, 'teens', 1, 'At what age did Josiah begin to seek the God of David his father, and what did he do in his twelfth year?', 'In his eighth year as king, being sixteen, he began to seek God; in his twelfth year he began to purge Judah and Jerusalem of the high places, groves, carved images, and molten images', 'At age eight he began to seek God; at twelve he built the temple', 'At age eighteen he began to seek God; at twenty-two he purged Judah', 'At age sixteen he began to seek God; at twenty he cleansed the temple', 'a', '2 Chronicles 34:3 — "For in the eighth year of his reign, while he was yet young, he began to seek after the God of David his father: and in the twelfth year he began to purge Judah and Jerusalem from the high places, and the groves, and the carved images, and the molten images."'),
('2 Chronicles', 34, 'teens', 2, 'Where did the messengers go to seek a prophetic word after the book of the law was found?', 'To Huldah the prophetess, the wife of Shallum, keeper of the wardrobe, who dwelt in Jerusalem in the college', 'To the prophet Jeremiah at Anathoth', 'To the prophet Zephaniah in the temple courts', 'To the priest Hilkiah who had found the book', 'a', '2 Chronicles 34:22 — "And Hilkiah, and they that the king had appointed, went to Huldah the prophetess...and they spake to her to that effect."'),
('2 Chronicles', 34, 'teens', 3, 'What did Huldah prophesy concerning Jerusalem and Josiah personally?', 'She said disaster would come on Jerusalem and its inhabitants because they had forsaken God, but because Josiah''s heart was tender and he humbled himself before God, he would be gathered to his fathers in peace and not see the evil', 'She said God would spare Jerusalem completely because of the reforms', 'She said Josiah himself would be punished for the sins of Manasseh', 'She said Jerusalem would fall only after Josiah''s children died', 'a', '2 Chronicles 34:24-28 — "Thus saith the LORD, Behold, I will bring evil upon this place...Because thine heart was tender, and thou didst humble thyself before God...thou shalt be gathered to thy grave in peace."'),
('2 Chronicles', 34, 'teens', 4, 'What covenant did Josiah make after reading the book of the law to all the inhabitants of Jerusalem?', 'He stood in his place and made a covenant before the LORD to walk after the LORD and to keep his commandments with all his heart and soul', 'He swore an oath to destroy all idol worship within three years', 'He signed a treaty with the priests pledging temple support', 'He promised to follow the law only if God spared Jerusalem', 'a', '2 Chronicles 34:31 — "And the king stood in his place, and made a covenant before the LORD, to walk after the LORD, and to keep his commandments, and his testimonies, and his statutes, with all his heart, and with all his soul."'),
('2 Chronicles', 34, 'teens', 5, 'What happened throughout all the lands of Israel under Josiah''s purge?', 'He made all that were present in Israel to serve the LORD their God, and all his days they departed not from following the LORD God of their fathers', 'He destroyed only the high places in Judah but left Israel untouched', 'He focused entirely on Jerusalem and left the provinces to govern themselves', 'He destroyed the idols but could not change the people''s hearts', 'a', '2 Chronicles 34:33 — "And Josiah took away all the abominations out of all the countries that pertained to the children of Israel...and made all that were present in Israel to serve, even to serve the LORD their God."'),
-- Adults
('2 Chronicles', 34, 'adults', 1, 'What does the description of Josiah walking "in the ways of David his father, and declined neither to the right hand, nor to the left" tell us about the Chronicler''s highest standard for kingship?', 'The Davidic standard — undivided faithfulness without deviation — is the supreme measure of a king in Chronicles, achieved fully only by Josiah and his ancestor Hezekiah among the later kings', 'It means Josiah avoided all military campaigns', 'It means he refused to take political advice from counsellors', 'It describes his consistency in administration rather than religion', 'a', '2 Chronicles 34:2 — "And he did that which was right in the sight of the LORD, and walked in the ways of David his father, and declined neither to the right hand, nor to the left."'),
('2 Chronicles', 34, 'adults', 2, 'What does the detail that Josiah began seeking God "while he was yet young" — in his eighth year as king, aged sixteen — reveal about the Chronicler''s theology of personal initiative?', 'It shows that genuine seeking of God is a personal decision that does not wait for instruction or crisis — Josiah sought God without external compulsion, from inner conviction while still a youth', 'It shows the priests had trained him in secret since birth', 'It shows prophetic pressure forced him to seek God early', 'It shows political instability drove him to seek divine support', 'a', '2 Chronicles 34:3 — "For in the eighth year of his reign, while he was yet young, he began to seek after the God of David his father."'),
('2 Chronicles', 34, 'adults', 3, 'How does the physical destruction of the bones of the idolatrous priests on their own altars fulfil ancient prophetic words, and what precedent is cited?', 'The text implies fulfilment of the man of God''s prophecy to Jeroboam at Bethel, though the Chronicler focuses on the moral cleansing of northern territories as part of Josiah''s pan-Israelite reform', 'It fulfilled a specific commandment of Moses', 'It was a military tactic to prevent the altars being rebuilt', 'It fulfilled a prophecy of Isaiah concerning Judah', 'a', '2 Chronicles 34:5 — "And he burnt the bones of the priests upon their altars, and cleansed Judah and Jerusalem," — parallel to the prophecy of 1 Kings 13:2 about the altar at Bethel.'),
('2 Chronicles', 34, 'adults', 4, 'What does the discovery of the book of the law during temple repairs suggest about the spiritual condition of Judah under Manasseh and Amon?', 'That the word of God had been so thoroughly suppressed and neglected during their reigns that even the temple workers rediscovered it only by accident — the depth of spiritual darkness under which Judah had lived', 'That the book had been deliberately hidden by priests for safekeeping', 'That the book had been recently written and placed there', 'That it was a different text from the one Moses wrote', 'a', '2 Chronicles 34:14 — "Hilkiah the priest found a book of the law of the LORD given by Moses," — found during routine repair work, not a formal search, implying it had been entirely lost from public use.'),
('2 Chronicles', 34, 'adults', 5, 'What does Huldah''s oracle reveal about the theological relationship between the text of the law and divine judgment?', 'The law functions as a covenant document — its rediscovery activated its curses which had been dormant; the people''s ignorance did not cancel their culpability under it', 'The law was merely advisory and disobedience carried no automatic consequence', 'The curses applied only to Israel, not to Judah', 'God''s judgment was based on behavior alone without reference to written law', 'a', '2 Chronicles 34:24 — "Thus saith the LORD, Behold, I will bring evil upon this place, and upon the inhabitants thereof, even all the curses that are written in the book," — showing the law''s self-executing covenantal character.'),
('2 Chronicles', 34, 'adults', 6, 'What does Huldah''s description of Josiah''s tender heart and humility specify as the grounds for his personal exemption from seeing Jerusalem''s destruction?', 'Because his heart was tender and he humbled himself before God when he heard God''s words against this place and its inhabitants, and wept before God — humility and grief over sin secured him personal peace', 'Because he had kept every commandment perfectly from youth', 'Because the priests had interceded for him', 'Because he had made large donations to the temple treasury', 'a', '2 Chronicles 34:27 — "Because thine heart was tender, and thou didst humble thyself before God, when thou heardest his words against this place, and against the inhabitants thereof, and humbledst thyself before me, and didst rend thy clothes, and weep before me; I have even heard thee also, saith the LORD."'),
('2 Chronicles', 34, 'adults', 7, 'What administrative detail in the temple repair account shows the moral integrity of those overseeing the work?', 'The money given for the work was not accounted to them for it was done faithfully — the workmen dealing faithfully did not need to give account of each payment', 'A detailed audit was conducted by the Levites monthly', 'The priests themselves collected and counted all funds', 'The king''s scribe personally verified every expenditure', 'a', '2 Chronicles 34:12 — "And the men did the work faithfully...because they dealt faithfully," — the Chronicler commends the integrity of those overseeing the restoration.'),
('2 Chronicles', 34, 'adults', 8, 'What is the significance of the covenant that all the people entered into in this chapter, and how does it mirror earlier covenants in Chronicles?', 'It mirrors Asa''s covenant renewal and Hezekiah''s dedication — the Chronicler presents corporate covenant renewal as the culminating act of each major reform, binding the whole community to God''s law collectively', 'It was an entirely new type of legal document invented by Josiah''s scribes', 'It was a political treaty between the king and the priestly class', 'It was binding only on the priests and Levites, not the common people', 'a', '2 Chronicles 34:32 — "And he caused all that were present in Jerusalem and Benjamin to stand to it. And the inhabitants of Jerusalem did according to the covenant of God," — echoing the pattern of covenant renewals across Chronicles.');

-- ═══ 2 Chronicles Chapter 35 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 35, 'kids', 1, 'What great feast did Josiah keep that had not been kept like it in Israel for a long time?', 'The passover', 'The feast of tabernacles', 'The day of atonement', 'The feast of first fruits', 'a', '2 Chronicles 35:1 — "Moreover Josiah kept a passover unto the LORD in Jerusalem: and they killed the passover on the fourteenth day of the first month."'),
('2 Chronicles', 35, 'kids', 2, 'Where did Josiah die in battle?', 'At Megiddo', 'At Jerusalem', 'At Lachish', 'At Jericho', 'a', '2 Chronicles 35:22 — "Nevertheless Josiah would not turn his face from him, but disguised himself, that he might fight with him, and hearkened not unto the words of Necho from the mouth of God, and came to fight in the valley of Megiddo."'),
('2 Chronicles', 35, 'kids', 3, 'Who wrote a lament for Josiah that became a custom in Israel?', 'Jeremiah', 'Isaiah', 'Ezekiel', 'Daniel', 'a', '2 Chronicles 35:25 — "And Jeremiah lamented for Josiah: and all the singing men and the singing women spake of Josiah in their lamentations to this day, and made them an ordinance in Israel."'),
-- Teens
('2 Chronicles', 35, 'teens', 1, 'What did Josiah command the Levites to do with the holy ark at the Passover?', 'Put the holy ark in the house which Solomon the son of David king of Israel did build; it shall not be a burden upon your shoulders — now serve the LORD your God', 'Carry the ark in procession around the city first', 'Take the ark to the threshingfloor where David had brought it', 'Polish and rededicate the ark before the feast', 'a', '2 Chronicles 35:3 — "And said unto the Levites that taught all Israel, which were holy unto the LORD, Put the holy ark in the house which Solomon the son of David king of Israel did build; it shall not be a burden upon your shoulders."'),
('2 Chronicles', 35, 'teens', 2, 'How many animals did Josiah provide for the Passover offerings, and what did the princes contribute?', 'Josiah gave thirty thousand lambs and kids and three thousand bullocks; the chief of the priests gave two thousand six hundred small cattle and three hundred oxen; and other leaders gave large amounts', 'Josiah gave a hundred thousand lambs and ten thousand bulls', 'Only the temple treasury animals were used', 'Each family brought their own animal with no royal provision', 'a', '2 Chronicles 35:7-9 — "And Josiah gave to the people...thirty thousand, and three thousand bullocks...And Hilkiah and Zechariah and Jehiel...gave unto the priests for the passover offerings two thousand and six hundred small cattle."'),
('2 Chronicles', 35, 'teens', 3, 'What king of Egypt came against Josiah and what warning did he give?', 'Necho king of Egypt came against him and said God had commanded him to make haste, warning Josiah to forbear from interfering with God lest God destroy him', 'Pharaoh Hophra came seeking tribute and warned Josiah not to resist', 'Pharaoh sent ambassadors asking for peace and Josiah refused', 'An unnamed Egyptian king attacked without warning', 'a', '2 Chronicles 35:20-21 — "Necho king of Egypt came up to fight against Carchemish by Euphrates: and Josiah went out against him...And he sent ambassadors to him, saying, What have I to do with thee, thou king of Judah?...God commanded me to make haste: forbear thee from meddling with God, who is with me, that he destroy thee not."'),
('2 Chronicles', 35, 'teens', 4, 'How was Josiah wounded in battle and what happened to him?', 'The archers shot at king Josiah; he said take me away for I am sore wounded, and his servants took him out of his chariot and he died and was buried in Jerusalem', 'Josiah was killed instantly by a spear in the first charge', 'Josiah escaped wounded but died of fever two weeks later', 'Josiah was captured and executed by the Egyptians', 'a', '2 Chronicles 35:23-24 — "And the archers shot at king Josiah; and the king said to his servants, Have me away; for I am sore wounded. His servants therefore took him out of that chariot, and put him in the second chariot that he had...and he died, and was buried in one of the sepulchres of his fathers."'),
('2 Chronicles', 35, 'teens', 5, 'What does the Chronicler say about how Josiah''s Passover compared to all previous Passovers?', 'There was no passover like to that kept in Israel from the days of Samuel the prophet; neither did all the kings of Israel keep such a passover as Josiah kept', 'It was only the second greatest after Hezekiah''s', 'It equalled the Passover of the Exodus generation', 'It was greater than Solomon''s dedication feast', 'a', '2 Chronicles 35:18 — "And there was no passover like to that kept in Israel from the days of Samuel the prophet; neither did all the kings of Israel keep such a passover as Josiah kept."'),
-- Adults
('2 Chronicles', 35, 'adults', 1, 'What does the detail that Josiah told the Levites "the ark shall not be a burden upon your shoulders" reveal about the nature of his reform and the state of Levitical service?', 'It suggests the Levites had been carrying the ark between locations, probably due to the disruptions of Manasseh''s reign — Josiah was restoring the Solomonic arrangement where the ark rested permanently in the temple', 'It shows Josiah wanted the Levites to focus on music only', 'It was a practical order about reducing physical strain', 'It shows the ark had been lost and was only recently recovered', 'a', '2 Chronicles 35:3 — "Put the holy ark in the house which Solomon the son of David king of Israel did build; it shall not be a burden upon your shoulders: serve now the LORD your God."'),
('2 Chronicles', 35, 'adults', 2, 'What is the theological significance of Josiah''s Passover surpassing even Samuel''s — the first mention of a notable Passover since the Exodus generation?', 'It places Josiah''s reform at the apex of the entire history of Israel''s covenant worship, suggesting the Davidic-Solomonic ideal was most completely realized under Josiah before the final collapse', 'It is simply a superlative to honour Josiah as a military leader', 'It shows the other Passovers were performed incorrectly', 'It is an exaggeration by the Chronicler for rhetorical effect', 'a', '2 Chronicles 35:18 — "There was no passover like to that kept in Israel from the days of Samuel," — elevating Josiah''s covenant fidelity above all predecessors.'),
('2 Chronicles', 35, 'adults', 3, 'What does the Chronicler''s comment that Josiah "hearkened not unto the words of Necho from the mouth of God" reveal about divine speech through unexpected channels?', 'It reveals the remarkable principle that God can speak truth through a pagan king — Josiah''s failure was not discerning God''s word because of where it came from, showing divine speech transcends expected sources', 'It shows Necho was secretly a worshipper of the God of Israel', 'It shows Josiah was spiritually in decline and ignoring all prophets', 'It shows the Chronicler blamed Necho rather than Josiah for the death', 'a', '2 Chronicles 35:22 — "And hearkened not unto the words of Necho from the mouth of God, and came to fight in the valley of Megiddo."'),
('2 Chronicles', 35, 'adults', 4, 'How does the Chronicler''s use of retribution theology handle the apparently unjust death of the righteous Josiah at Megiddo?', 'The Chronicler explains it as Josiah''s single act of disobedience — not heeding God''s word spoken through Necho — receiving its appropriate consequence, maintaining the principle that even righteous kings are not exempt from judgment for specific acts of disobedience', 'The Chronicler admits this is an exception to retribution theology that he cannot explain', 'The Chronicler blames the Assyrians and Egyptians without attributing fault to Josiah', 'The Chronicler says Josiah''s death was entirely mysterious and not retributive', 'a', '2 Chronicles 35:22 — "And hearkened not unto the words of Necho from the mouth of God," — the single act of disobedience that explains the otherwise puzzling death of Judah''s most righteous king.'),
('2 Chronicles', 35, 'adults', 5, 'What was the nationwide mourning response to Josiah''s death, and how does the Chronicler preserve it for future generations?', 'All Judah and Jerusalem mourned for Josiah; Jeremiah lamented for him and all singers made lamentations for Josiah which became an ordinance in Israel, written in the lamentations', 'Only the priests mourned formally while the people returned to their work', 'A seven-day fast was declared throughout the kingdom', 'The mourning lasted only one day before the new king was crowned', 'a', '2 Chronicles 35:24-25 — "And all Judah and Jerusalem mourned for Josiah. And Jeremiah lamented for Josiah: and all the singing men and the singing women spake of Josiah in their lamentations to this day, and made them an ordinance in Israel."'),
('2 Chronicles', 35, 'adults', 6, 'What do the specific contributions of Josiah, the chief priests, and the Levitical leaders reveal about the communal nature of the Passover?', 'It was a thoroughly communal celebration where leadership at every level — royal, priestly, and Levitical — contributed generously to ensure even the poorest worshipper could fully participate in the feast', 'It was primarily a royal celebration funded from the treasury', 'It shows priestly wealth had increased since Hezekiah''s time', 'It shows each family still had to provide its own animals', 'a', '2 Chronicles 35:7-9 — "And Josiah gave to the people...thirty thousand, and three thousand bullocks...Hilkiah and Zechariah and Jehiel...gave unto the priests for the passover offerings two thousand and six hundred small cattle, and three hundred oxen. Conaniah also...gave unto the Levites for passover offerings five thousand small cattle."'),
('2 Chronicles', 35, 'adults', 7, 'What was the order of service at the Passover, and what role did the Levites play in killing the Passover lambs?', 'The Levites killed the passover for all the children of the people while the priests sprinkled the blood; the Levites divided themselves by fathers'' houses into courses to serve efficiently', 'The priests alone killed and the Levites observed', 'Each family head killed his own animal without priestly assistance', 'The king''s servants slaughtered all the animals centrally', 'a', '2 Chronicles 35:11-12 — "And they killed the passover, and the priests sprinkled the blood from their hands, and the Levites flayed them. And they removed the burnt offerings, that they might give according to the divisions of the families of the people."'),
('2 Chronicles', 35, 'adults', 8, 'What does the summary verdict on Josiah''s reign — "there was no king before him that turned to the LORD with all his heart, and with all his soul, and with all his might" — parallel, and what does this parallel teach about Josiah''s place in Israel''s history?', 'It parallels the Deuteronomic praise of Moses in Deuteronomy 34:10 and the commendation of Hezekiah in 2 Kings 18:5, placing Josiah alongside the greatest figures of Israel''s covenant history', 'It shows Josiah was greater than David in every way', 'It is unique to Chronicles and has no parallel in other books', 'It refers only to his military achievements against idolatry', 'a', '2 Chronicles 35:26 — "Now the rest of the acts of Josiah, and his goodness, according to that which was written in the law of the LORD," — the Chronicler summarizes him as the fullest embodiment of covenant fidelity.');

-- ═══ 2 Chronicles Chapter 36 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 36, 'kids', 1, 'What happened to the temple in Jerusalem when Babylon conquered Judah?', 'They burnt the house of God, and brake down the wall of Jerusalem', 'They carried the temple away stone by stone', 'They turned it into a palace for the Babylonian governor', 'They sealed the temple shut and left it standing', 'a', '2 Chronicles 36:19 — "And they burnt the house of God, and brake down the wall of Jerusalem, and burnt all the palaces thereof with fire, and destroyed all the goodly vessels thereof."'),
('2 Chronicles', 36, 'kids', 2, 'After the exile, which great king gave permission for the Jews to return and rebuild the temple?', 'Cyrus king of Persia', 'Darius king of Persia', 'Artaxerxes king of Persia', 'Ahasuerus king of Persia', 'a', '2 Chronicles 36:22-23 — "Now in the first year of Cyrus king of Persia, that the word of the LORD spoken by the mouth of Jeremiah might be accomplished, the LORD stirred up the spirit of Cyrus king of Persia, that he made a proclamation throughout all his kingdom."'),
('2 Chronicles', 36, 'kids', 3, 'How many years did Judah stay in exile in Babylon?', 'Seventy years', 'Forty years', 'Fifty years', 'One hundred years', 'a', '2 Chronicles 36:21 — "To fulfil the word of the LORD by the mouth of Jeremiah, until the land had enjoyed her sabbaths: for as long as she lay desolate she kept sabbath, to fulfil threescore and ten years."'),
-- Teens
('2 Chronicles', 36, 'teens', 1, 'What were the names of the last four kings of Judah and in what order did they reign?', 'Jehoahaz, then Jehoiakim, then Jehoiachin, then Zedekiah', 'Jehoiakim, then Jehoahaz, then Zedekiah, then Jehoiachin', 'Zedekiah, then Jehoiachin, then Jehoiakim, then Jehoahaz', 'Jehoiachin, then Jehoahaz, then Jehoiakim, then Zedekiah', 'a', '2 Chronicles 36:1-11 — Jehoahaz reigned three months (v.2), then Jehoiakim eleven years (v.5), then Jehoiachin three months and ten days (v.9), then Zedekiah eleven years (v.11).'),
('2 Chronicles', 36, 'teens', 2, 'What did Nebuchadnezzar do when Zedekiah rebelled against him?', 'He came up against Jerusalem and bound Zedekiah with chains to carry him to Babylon', 'He sent an army to besiege Lachish first', 'He demanded tribute rather than attacking', 'He sent a message asking Zedekiah to submit peacefully', 'a', '2 Chronicles 36:6 — "Against him came up Nebuchadnezzar king of Babylon, and bound him in fetters, to carry him to Babylon." (Regarding Jehoiakim; similarly 36:17 regarding the final destruction and Zedekiah''s capture described in the same siege narrative.)'),
('2 Chronicles', 36, 'teens', 3, 'What does the Chronicler say the leaders and priests did that caused God to finally send the Babylonians as his instrument of judgment?', 'They mocked the messengers of God, despised his words, and misused his prophets, until the wrath of the LORD arose against his people till there was no remedy', 'They refused to pay tribute to the priests', 'They failed to observe the Sabbath year for one generation', 'They allowed intermarriage with Canaanites', 'a', '2 Chronicles 36:16 — "But they mocked the messengers of God, and despised his words, and misused his prophets, until the wrath of the LORD arose against his people, till there was no remedy."'),
('2 Chronicles', 36, 'teens', 4, 'What did Nebuchadnezzar take away to Babylon from the temple?', 'The vessels of the house of God, great and small, and the treasures of the house of the LORD, and the treasures of the king and of his princes', 'Only the ark of the covenant', 'Only the golden lampstand and table of showbread', 'Only the bronze pillars Jachin and Boaz', 'a', '2 Chronicles 36:18 — "And all the vessels of the house of God, great and small, and the treasures of the house of the LORD, and the treasures of the king, and of his princes; all these he brought to Babylon."'),
('2 Chronicles', 36, 'teens', 5, 'What was the condition of the land of Judah after the exile, and what prophetic word did this fulfil?', 'The land kept sabbath, lying desolate to fulfil threescore and ten years, according to the word of the LORD by the mouth of Jeremiah', 'The land was immediately resettled by Babylon with new peoples', 'The land remained fertile and was farmed by the remaining poor', 'The land lay desolate for forty years only', 'a', '2 Chronicles 36:21 — "To fulfil the word of the LORD by the mouth of Jeremiah, until the land had enjoyed her sabbaths: for as long as she lay desolate she kept sabbath, to fulfil threescore and ten years."'),
-- Adults
('2 Chronicles', 36, 'adults', 1, 'What does the rapid succession of four kings in chapter 36 reveal about the Chronicler''s understanding of the end of the Davidic dynasty?', 'It reveals the accelerating decay of the covenant community — each reign is shorter and more thoroughly evil, showing that persistent rejection of prophetic warning leads to irreversible momentum toward judgment', 'It shows the kings were simply unlucky politically', 'It shows the Babylonians were unusually aggressive in this period', 'It shows God had already decided to end the dynasty regardless of their behavior', 'a', '2 Chronicles 36:1-11 — Four kings in rapid succession: Jehoahaz (3 months), Jehoiakim (11 years, evil), Jehoiachin (3 months), Zedekiah (11 years, evil) — the Chronicler compresses their failures to emphasize the inevitability of judgment.'),
('2 Chronicles', 36, 'adults', 2, 'What does the Chronicler''s statement that God "had compassion on his people, and on his dwelling place" by repeatedly sending messengers reveal about his character before the final judgment?', 'It reveals that God''s judgment came only after sustained, patient warning — the exile was not arbitrary anger but the reluctant conclusion of divine compassion exhausted by persistent mockery of prophets', 'It reveals God was slow to judge because of political considerations', 'It reveals the prophets had persuaded God to delay judgment', 'It reveals God was uncertain whether to judge Israel', 'a', '2 Chronicles 36:15 — "And the LORD God of their fathers sent to them by his messengers, rising up betimes, and sending; because he had compassion on his people, and on his dwelling place."'),
('2 Chronicles', 36, 'adults', 3, 'What is the theological significance of the phrase "till there was no remedy" — what does it tell us about the limits of divine patience in Chronicles?', 'It marks the point where the covenant''s curses became irresistible — not because God ceased to be merciful but because the people had passed through every available means of grace and chosen rejection each time, exhausting the covenantal mechanism of restoration', 'It shows God''s mercy is finite and runs out automatically after a set number of offences', 'It shows the people had become too numerous for prophets to reach', 'It shows the temple''s destruction removed the only means of atonement', 'a', '2 Chronicles 36:16 — "Until the wrath of the LORD arose against his people, till there was no remedy," — the Chronicler''s most solemn phrase, marking the terminal point of the retribution cycle.'),
('2 Chronicles', 36, 'adults', 4, 'How does the land''s sabbath rest during the exile function as a theological statement about Judah''s failure to observe the sabbatical year laws?', 'The land received by force the sabbath rests that the people had denied it — God''s law was enforced through judgment when covenant obedience had failed, showing the law''s self-fulfilling character within history', 'The sabbath rest was purely coincidental to the length of the exile', 'The sabbath rest refers only to spiritual rest, not literal land fallow', 'God shortened the exile to ensure exactly seventy sabbath years', 'a', '2 Chronicles 36:21 — "Until the land had enjoyed her sabbaths: for as long as she lay desolate she kept sabbath," — the land received by divine compulsion what Israel had refused to give voluntarily.'),
('2 Chronicles', 36, 'adults', 5, 'What is the literary and theological function of the book of Chronicles ending with Cyrus''s decree rather than with the destruction or the exile?', 'It provides a note of hope — the Chronicler ends with an open door of restoration, showing that even total judgment does not nullify God''s covenant purposes; the decree of Cyrus is the beginning of fulfilment, not an ending', 'It shows the Chronicler was writing after the return and wanted to end positively for political reasons', 'It shows the Chronicler considered the exile unimportant compared to the return', 'It shows the exile was too traumatic for the Chronicler to describe in detail', 'a', '2 Chronicles 36:23 — "Thus saith Cyrus king of Persia, All the kingdoms of the earth hath the LORD God of heaven given me; and he hath charged me to build him an house in Jerusalem...Who is there among you of all his people? The LORD his God be with him, and let him go up."'),
('2 Chronicles', 36, 'adults', 6, 'What does the fulfilment of Jeremiah''s seventy-year prophecy through Cyrus''s decree reveal about the Chronicler''s view of prophetic authority?', 'That prophecy is the interpretive key to history — the exile and return were not geopolitical accidents but the precise fulfilment of a named prophet''s word, validating both the prophetic office and the reliability of God''s covenant promises', 'That only Jeremiah''s prophecies were accurate among all the prophets', 'That Cyrus somehow knew about Jeremiah''s prophecy and used it politically', 'That seventy years is a symbolic round number with no literal significance', 'a', '2 Chronicles 36:22 — "That the word of the LORD spoken by the mouth of Jeremiah might be accomplished," — the Chronicler frames the return explicitly as prophetic fulfilment.'),
('2 Chronicles', 36, 'adults', 7, 'How does the Chronicler''s description of Zedekiah''s relationship with Nebuchadnezzar and his rebellion function within the broader theological framework of the book?', 'Zedekiah''s breaking of his sworn oath to Nebuchadnezzar — stiffening his neck and hardening his heart against turning to the LORD — represents the final, definitive rejection of every form of covenantal obligation, completing the trajectory of apostasy', 'It is primarily a political narrative with no theological dimension', 'It shows Zedekiah was trying to save Judah from cultural absorption', 'It shows the Babylonian treaty was illegitimate and breaking it was justified', 'a', '2 Chronicles 36:13 — "And he also rebelled against king Nebuchadnezzar, who had made him swear by God: but he stiffened his neck, and hardened his heart from turning unto the LORD God of Israel."'),
('2 Chronicles', 36, 'adults', 8, 'What does the universal scope of Cyrus''s decree — "all the kingdoms of the earth hath the LORD God of heaven given me" — reveal about the Chronicler''s theology of nations and history?', 'It reveals that the God of Israel is the sovereign LORD of all history — not merely Israel''s tribal deity — whose purposes encompass and use even pagan empires to fulfil his covenant promises to his people, a thoroughly universalist conclusion to the book', 'It reveals Cyrus had converted to Judaism before issuing the decree', 'It reveals that Persia''s empire was a fulfilment of Israel''s original land promises', 'It reveals the Chronicler was apologetically defending Israel against Babylonian theology', 'a', '2 Chronicles 36:23 — "All the kingdoms of the earth hath the LORD God of heaven given me; and he hath charged me to build him an house in Jerusalem," — the pagan king acknowledging the God of heaven as sovereign, ending Chronicles on a note of universal divine sovereignty.');
